  ('science', '1', 2, '1.materials', NULL, 'Which material floats easily on water?', '["A metal nail","Wood","A brick","A heavy rock"]', 1, 'Wood is light and floats on water.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Which gives us light during the day?', '["The stars","The moon","A streetlight","The sun"]', 3, 'The sun lights up the day.', 10),
  ('science', '1', 2, '1.sky', NULL, 'We can see many tiny ___ in the night sky.', '["stars","rainbows","clouds only","suns"]', 0, 'Stars sparkle in the night sky.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The moon looks bright because it reflects light from the ___.', '["Earth","stars","sun","streetlights"]', 2, 'The moon has no light of its own; it reflects the sun.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The sun is actually a ___.', '["cloud","star","moon","planet"]', 1, 'The sun is a star that is close to us.', 10),
  ('science', '1', 2, '1.sky', NULL, 'During a clear day, the sky usually looks ___.', '["green","red","black","blue"]', 3, 'The clear daytime sky is blue.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Which looks bigger to us because it is much closer to Earth?', '["A distant planet","The moon","A faraway star","The whole sky"]', 1, 'The moon is close, so it looks big. Stars are far, so they look tiny.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Which part of a plant is usually green and makes food from sunlight?', '["The leaves","The soil","The roots","The seed"]', 0, 'Leaves use sunlight to make food for the plant.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Besides sunlight, plants also need ___ to grow.', '["rocks","water","toys","candy"]', 1, 'Plants need water and sunlight to grow.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby cow is called a ___.', '["kitten","chick","puppy","calf"]', 3, 'A baby cow is a calf.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby frog is called a ___.', '["foal","tadpole","joey","cub"]', 1, 'A baby frog hatches as a tadpole and grows legs later.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'In which season do many leaves fall from the trees?', '["Summer","Winter","Spring","Fall"]', 3, 'Leaves drop in the fall (autumn).', 10),
  ('science', '1', 2, '1.shadow', NULL, 'A shadow forms when something blocks the ___.', '["wind","light","sound","water"]', 1, 'A shadow appears where an object blocks light.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material is clear so you can see through it?', '["Wood","Glass","Cloth","Metal"]', 1, 'Glass is clear, so light passes through it.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The sun is really a ___.', '["star","moon","cloud","planet"]', 0, 'The sun is the closest star to Earth.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The moon looks bright because it reflects light from the ___.', '["streetlights","clouds","stars","sun"]', 3, 'The moon has no light of its own; it reflects the sun''s light.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby horse is called a ___.', '["foal","piglet","joey","cub"]', 0, 'A young horse is called a foal.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby deer is called a ___.', '["piglet","cub","duckling","fawn"]', 3, 'A young deer is called a fawn.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby sheep grows up to look most like a ___.', '["grown sheep","grown dog","grown bird","grown cow"]', 0, 'Baby animals grow up to look like their own parents, so a lamb becomes a grown sheep.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby goose is called a ___.', '["piglet","lamb","gosling","kid"]', 2, 'A young goose is called a gosling.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material is best for making a window so you can see outside?', '["brick","wood","glass","cloth"]', 2, 'Glass is clear, so we use it for windows to see through.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which object is usually hard and does not bend?', '["a towel","a rubber band","a rock","a sponge"]', 2, 'A rock is hard and stiff, while the others are soft or bendy.', 10);
insert into public.questions (subject_id, grade, difficulty, skill, standard, prompt, choices, answer_index, explanation, xp) values
  ('science', '1', 2, '1.materials', NULL, 'A balloon is usually made of ___.', '["rubber","glass","wood","metal"]', 0, 'Balloons are made of stretchy rubber so they can fill with air.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which is the best material for the pages of a book?', '["rubber","paper","glass","metal"]', 1, 'Paper is thin and easy to write or print on, so books use paper pages.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material is stretchy so it can pull longer and snap back?', '["a glass marble","a rubber band","a wooden ruler","a metal coin"]', 1, 'A rubber band stretches and then springs back to its shape.', 10),
  ('science', '1', 2, '1.plants', NULL, 'What color are most leaves?', '["orange","blue","green","black"]', 2, 'Most leaves are green, which helps them make food from sunlight.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Plants make their own food using light from the ___.', '["stars","moon","clouds","sun"]', 3, 'Plants use sunlight to make their own food.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Bees help plants by moving ___ from flower to flower.', '["roots","rocks","leaves","pollen"]', 3, 'Bees carry pollen between flowers, which helps plants make seeds.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Which is the part of a plant that catches sunlight to make food?', '["fruit","leaf","seed","root"]', 1, 'Leaves catch sunlight and use it to help make the plant''s food.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'Which clothes would you most likely wear in summer?', '["a thick scarf","a heavy coat and gloves","shorts and a t-shirt","snow boots"]', 2, 'Summer is warm, so you wear light clothes like shorts and a t-shirt.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'Days are usually the longest and have the most daylight in ___.', '["summer","none","winter","fall"]', 0, 'Summer has the longest days with the most daylight.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'In which season do farmers often harvest, or pick, ripe crops like pumpkins?', '["summer","winter","spring","fall"]', 3, 'Many crops, like pumpkins, are picked in the fall harvest.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'Spring weather often brings more ___ that helps plants grow.', '["rain","sand","ice","snow"]', 0, 'Spring often brings rain, which helps plants grow.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'Where does a shadow appear?', '["up in the clouds","on the side away from the light","right on the light","inside the object"]', 1, 'A shadow falls on the side of an object away from the light.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'Can you have a shadow in a completely dark room with no light?', '["yes, always","no, you need light","only at night","only if it is cold"]', 1, 'Without any light there is nothing to block, so no shadow can form.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'What happens to a tree''s shadow as the sun moves across the sky during the day?', '["it turns red","it disappears all day","it stays exactly the same","it moves and changes length"]', 3, 'As the sun moves, the shadow moves and changes length through the day.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'Which would block the most light and make the darkest shadow?', '["a sheet of glass","a clear plastic sheet","a thin lace curtain","a thick wooden door"]', 3, 'A thick wooden door blocks all the light, making the darkest shadow.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The sun seems to ___ in the morning and set in the evening.', '["rise","disappear forever","fall to the ground","melt"]', 0, 'The sun appears to rise in the morning and set in the evening each day.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Why does the sun look bigger than the stars we see at night?', '["it is the only star","it is hotter","it is much closer to Earth","it is at night"]', 2, 'The sun looks bigger because it is much closer to Earth than other stars.', 10),
  ('science', '1', 2, '1.sky', NULL, 'When it is daytime where you live, it is mostly ___ in the sky.', '["dark","raining always","full of stars","light"]', 3, 'During the day the sky is light because the sun is up.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby sheep is called a ___.', '["lamb","calf","fawn","kit"]', 0, 'A young sheep is called a lamb.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby pig is called a ___.', '["foal","piglet","chick","kit"]', 1, 'A young pig is called a piglet.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'Which baby animal hatches from an egg?', '["calf","puppy","chick","kitten"]', 2, 'A chick hatches from an egg, while puppies, kittens, and calves are born live.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby lion is called a ___.', '["cub","foal","duckling","calf"]', 0, 'A young lion is called a cub.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material would make the best umbrella to keep rain off you?', '["tissue","plastic","paper","cotton cloth"]', 1, 'Plastic is waterproof, so rain runs off it instead of soaking through.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material would soak up spilled water the best?', '["a plastic plate","a paper towel","a metal pan","a glass jar"]', 1, 'A paper towel soaks up water, while metal, glass, and plastic do not.', 10),
  ('science', '1', 2, '1.materials', NULL, 'We can shape soft clay into different forms because it is ___.', '["bendable","shiny","cold","clear"]', 0, 'Clay is soft and bendable, so we can shape it many ways.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material is best for a swimming pool toy that floats?', '["foam","glass","stone","metal"]', 0, 'Foam is light and full of air, so it floats on water.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Which part of the plant grows down into the soil?', '["flower","leaf","roots","fruit"]', 2, 'Roots grow down into the soil to hold the plant and take in water.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Which of these is a plant?', '["a fish","a rock","a cloud","a tree"]', 3, 'A tree is a living plant, while a rock, cloud, and fish are not plants.', 10),
  ('science', '1', 2, '1.plants', NULL, 'What happens to a plant that never gets any water?', '["it turns blue","it dries up and dies","it grows faster","it floats away"]', 1, 'Plants need water, so a plant with no water will dry up and die.', 10),
  ('science', '1', 2, '1.plants', NULL, 'The thin stem under the soil and the roots help a plant by ___.', '["blowing wind","catching fish","making light","taking in water"]', 3, 'Roots take in water from the soil for the plant.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'Which season comes right after winter?', '["spring","fall","summer","none"]', 0, 'Spring comes right after winter in the order of seasons.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'Which clothes would you most likely wear in winter?', '["a warm coat","sandals","a swimsuit","a sun hat only"]', 0, 'Winter is cold, so you wear a warm coat to stay warm.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'Days are usually the shortest with the least daylight in ___.', '["winter","summer","fall","spring"]', 0, 'Winter has the shortest days with the least daylight.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'As seasons change, the weather mostly changes because of changes in ___.', '["the price of food","the number of cars","how warm or cold it is","the color of grass"]', 2, 'Seasons bring changes in how warm or cold the weather is.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'A shadow is usually the same ___ as the object that makes it.', '["weight","temperature","color","shape"]', 3, 'A shadow has the same shape as the object that blocks the light.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'At noon, when the sun is high overhead, your shadow is usually ___.', '["colorful","short","very long","behind the clouds"]', 1, 'When the sun is high at noon, shadows are short.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'If a flashlight shines on a ball, the shadow forms ___ the ball from the light.', '["behind","in front of","inside","above the light"]', 0, 'The shadow forms behind the ball, on the side away from the flashlight.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Which can we usually see in the sky only at night?', '["a rainbow","an airplane at noon","stars","the sun"]', 2, 'Stars are easiest to see at night when the sky is dark.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The bright flash we sometimes see in the sky during a storm is called ___.', '["a rainbow","lightning","the moon","a star"]', 1, 'Lightning is the bright flash of light seen in the sky during a storm.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Fluffy white shapes that float across the sky are called ___.', '["stars","shadows","planets","clouds"]', 3, 'Clouds are the white or gray shapes that float across the sky.', 10),
