  ('science', '1', 2, '1.materials', NULL, 'Which material is best for a warm winter coat?', '["wool","glass","stone","metal"]', 0, 'Wool is soft and traps heat to keep you warm.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material is clear AND can break if you drop it?', '["wool","glass","rubber","cardboard"]', 1, 'Glass is see-through and can shatter when dropped.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which object would feel rough to touch?', '["a smooth window","a silk scarf","sandpaper","an ice cube"]', 2, 'Sandpaper has a rough, bumpy surface.', 10),
