  ('science', '1', 2, '1.shadow', NULL, 'Which can make a shadow on a sunny day?', '["a beam of sunlight","empty air","a clear puddle of water","a fence"]', 3, 'A solid fence blocks sunlight and makes a shadow.', 10),
  ('science', '1', 2, '1.sky', NULL, 'What do we see in the sky during the day that gives us light and warmth?', '["the sun","a planet","the moon","the stars"]', 0, 'The sun shines in the daytime sky and gives us light and warmth.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Rain falls to the ground from ___.', '["the moon","clouds","the stars","the soil"]', 1, 'Rain falls from clouds in the sky down to the ground.', 10),
