  ('science', '1', 2, '1.sky', NULL, 'Which is true about the moon?', '["it is a cloud","we see it mostly at night","it gives off more light than the sun","it is hotter than the sun"]', 1, 'We usually see the moon at night in the sky.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby bear is called a ___.', '["kid","cub","gosling","tadpole"]', 1, 'A young bear is called a cub.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby goat is called a ___.', '["kid","foal","fawn","chick"]', 0, 'A young goat is called a kid.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby rabbit is called a ___.', '["kit","colt","fawn","chick"]', 0, 'A young rabbit is called a kit.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby kangaroo stays safe inside its mother''s ___.', '["nest","den","shell","pouch"]', 3, 'A baby kangaroo, or joey, rides and stays safe in its mother''s pouch.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material bends easily and is springy?', '["glass","rubber","brick","stone"]', 1, 'Rubber is bendy and springy, unlike hard brick, glass, or stone.', 10),
  ('science', '1', 2, '1.plants', NULL, 'A tiny young plant that just sprouted is called a ___.', '["branch","petal","trunk","seedling"]', 3, 'A young plant that has just started growing is called a seedling.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Which of these grows on a plant?', '["an apple","a shoe","a hammer","a brick"]', 0, 'An apple grows on an apple tree, which is a plant.', 10),
  ('science', '1', 2, '1.plants', NULL, 'A plant kept in a dark closet with no light will likely ___.', '["grow strong and green","turn into a rock","grow weak and pale","make more flowers"]', 2, 'Without light, a plant cannot make enough food and grows weak and pale.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'In which season might you build a snowman in cold places?', '["summer","winter","fall","spring"]', 1, 'Winter is cold and snowy, so it is the season for snowmen.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'The four seasons are spring, summer, fall, and ___.', '["winter","cold","rainy","sunny"]', 0, 'The four seasons are spring, summer, fall, and winter.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'Which season is a good time to plant a garden as it gets warmer?', '["none","spring","winter","fall"]', 1, 'Spring is warm and rainy, a good time to plant a garden.', 10),
  ('geography', '1', 2, 'geo.1.directions', NULL, 'What are the four main directions called?', '["One, Two, Three, Four","Red, Blue, Green, Yellow","Up, Down, Left, Right","North, South, East, West"]', 3, 'The four cardinal directions are North, South, East, and West.', 10),
  ('geography', '1', 2, 'geo.1.directions', NULL, 'On a map, which direction is usually at the top?', '["North","East","South","West"]', 0, 'On most maps, North points to the top.', 10),
