  ('geography', '1', 2, 'geo.1.community', NULL, 'A city is usually ___ than a small town.', '["smaller","rounder","bigger","colder"]', 2, 'A city has more people and buildings than a small town.', 10),
  ('geography', '1', 2, 'geo.1.directions', NULL, 'The sun SETS in the ___.', '["East","South","North","West"]', 3, 'The sun sets in the West each evening.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'A small hill is ___ than a mountain.', '["lower","colder","wetter","taller"]', 0, 'Hills are lower and smaller than mountains.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'A large body of water with land all around it is a ___.', '["lake","ocean","island","river"]', 0, 'A lake is water surrounded by land.', 10),
