  ('geography', '1', 2, 'geo.1.landforms', NULL, 'What do we call a wide, flat area of land with few trees?', '["a waterfall","a mountain","a cliff","a plain"]', 3, 'A plain is a wide, flat area of land.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'A dry place that gets very little rain and is often sandy is a ___.', '["ocean","glacier","swamp","desert"]', 3, 'A desert is a very dry place with little rain.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'A body of water with land all around it is a ___.', '["cliff","lake","mountain","valley"]', 1, 'A lake is water surrounded by land on all sides.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'Which landform is the tallest?', '["a mountain","a valley","a hill","a plain"]', 0, 'A mountain is the tallest of these landforms.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'A high wall of rock with a steep drop is a ___.', '["pond","cliff","plain","field"]', 1, 'A cliff is a tall, steep wall of rock.', 10),
  ('geography', '1', 2, 'geo.1.mapkey', NULL, 'A map key is also sometimes called a map ___.', '["legend","cookie","pillow","ladder"]', 0, 'A map key is also called a map legend.', 10),
