  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which group lists only NEEDS?', '["Stickers and balloons","Toys, candy, and games","Food, water, and shelter","Movies and ice cream"]', 2, 'Food, water, and shelter are needs everyone must have.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'A family has a little money. They should spend it FIRST on ___.', '["food for dinner","a new video game","a toy robot","fireworks"]', 0, 'Needs like food come before wants when money is limited.', 10),
