  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Maya is very thirsty. What does she NEED?', '["A toy car","Candy","A balloon","Water"]', 3, 'Water is a need because our bodies must have it to live.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which of these is a NEED?', '["Candy","A new toy","Food to eat","A balloon"]', 2, 'Food is a need because our bodies must have it to live.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which group has only things we NEED to live?', '["Candy, food, toy","Water, balloon, game","Toy, candy, game","Food, water, clothes"]', 3, 'Food, water, and clothes are all things we need to live.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Leo has money for ONE thing. He is hungry. The smart choice is ___.', '["a balloon","food","a toy","candy"]', 1, 'When you are hungry, food is the need you should pick first.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'A family must choose. Which is a NEED they should buy?', '["A video game","Candy","Food","A toy"]', 2, 'Food is a need, so the family should buy it before wants.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'A doctor giving you a checkup is an example of a ___.', '["good","coin","service","toy"]', 2, 'A checkup is work the doctor does for you, so it is a service.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'A pair of shoes you can wear is a ___.', '["job","coin","good","service"]', 2, 'Shoes are a good because they are an object you can hold and use.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which one is a GOOD, an object you can wear?', '["A hat","Cooking dinner for someone","Fixing a bike","Painting a house"]', 0, 'A hat is a good because it is an object you can touch and wear.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'A baker making bread for you to buy is making a ___.', '["service","good","need","coin"]', 1, 'Bread is an object you can hold, so the baker makes a good.', 10),
