  ('economics', '1', 2, 'econ.1.jobs', NULL, 'A person who helps you find and check out books at the library is a ___.', '["farmer","librarian","baker","pilot"]', 1, 'A librarian''s job is to help people find and borrow books.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'A person who cooks food at a restaurant has the job of a ___.', '["pilot","banker","farmer","chef"]', 3, 'A chef''s job is to cook food for people at a restaurant.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'A need is something a person ___ to live.', '["never uses","gives away","wants for fun","must have"]', 3, 'A need is something we must have to stay alive and healthy.', 10),
