  ('economics', '1', 2, 'econ.1.needswants', NULL, 'A place to live, like a home, is a ___.', '["toy","need","want","game"]', 1, 'Shelter such as a home is a need that keeps us safe.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which sentence is TRUE?', '["We can live without clothes.","We can live without food.","We can live without water.","We can live without a toy."]', 3, 'A toy is a want, so we can live without it.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which is something you NEED to stay alive?', '["A balloon","A game","Candy","Water"]', 3, 'Water is a need because our bodies cannot live without it.', 10),
