  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which of these is a GOOD you can hold?', '["A haircut","A loaf of bread","A piano lesson","A bus ride"]', 1, 'Bread is a good because it is an object you can hold.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'A bus driver taking you to school is giving a ___.', '["toy","coin","service","good"]', 2, 'Driving you to school is work done for you, so it is a service.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'A dentist cleaning your teeth is an example of a ___.', '["service","toy","good","coin"]', 0, 'Cleaning your teeth is work the dentist does for you, a service.', 10),
