  ('economics', '1', 2, 'econ.1.jobs', NULL, 'A person who fixes teeth has the job of a ___.', '["painter","pilot","dentist","farmer"]', 2, 'A dentist''s job is to take care of people''s teeth.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'A person who keeps streets safe and helps people in trouble is a ___.', '["police officer","pilot","farmer","baker"]', 0, 'A police officer''s job is to keep people safe and follow the law.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'What is one reason people pick a job they are good at?', '["To never get paid","They can do it well","To stay tired","To do it badly"]', 1, 'People often pick jobs they are good at so they can do them well.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'A want is something that is ___ but not needed to live.', '["nice to have","bad for you","required to live","always free"]', 0, 'A want is nice to have but you can live without it.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Sam wants candy AND needs food. What should he buy FIRST?', '["Neither one","Candy","Food","A toy"]', 2, 'Needs like food come before wants like candy.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Your body needs ___ every night to feel rested.', '["candy","games","sleep","toys"]', 2, 'Sleep is a need that helps your body rest and grow.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'A bottle of clean water is best called a ___.', '["want","game","need","gift"]', 2, 'Clean water is a need because our bodies must have it.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Going to an amusement park is a ___.', '["home","need","want","food"]', 2, 'A trip to an amusement park is fun but not needed to live.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which one is a GOOD you can hold?', '["Cutting hair","Driving a bus","Teaching class","An apple"]', 3, 'An apple is a good because it is an object you can hold.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'A teacher helping students learn is providing a ___.', '["service","toy","good","coin"]', 0, 'Teaching is work done for students, which makes it a service.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which is a GOOD and not a service?', '["A pencil","A car wash","A music lesson","A haircut"]', 0, 'A pencil is an object you can hold, which makes it a good.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which list has only GOODS?', '["Ball, checkup, apple","Apple, bus ride, book","Haircut, ball, book","Ball, book, apple"]', 3, 'A ball, a book, and an apple are all objects you can hold.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which one can you touch and hold, making it a GOOD?', '["A house painting","A car ride","A toy truck","A guitar lesson"]', 2, 'A toy truck is an object you can hold, so it is a good.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'How many cents is one penny worth?', '["10 cents","1 cent","5 cents","25 cents"]', 1, 'A penny is worth one cent.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'Saving your money means you ___ it now to use it later.', '["lose","keep","throw away","spend"]', 1, 'Saving means keeping money now so you can use it later.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'Which is money you could spend at a store?', '["A stick","A rock","A leaf","A dollar bill"]', 3, 'A dollar bill is money you can use to buy things.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'A nickel and a dime together make ___ cents.', '["10 cents","20 cents","5 cents","15 cents"]', 3, 'A nickel is 5 cents and a dime is 10 cents, which add up to 15.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'Why do most grown-ups go to work at a job?', '["To skip lunch","To earn money","To get tired","To stay home"]', 1, 'People work at jobs to earn money to buy needs and wants.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'The money a person earns from a job is called their ___.', '["income","gift","game","toy"]', 0, 'Income is the money a person earns from working at a job.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'People use the money they earn from a job to ___ things they need.', '["throw away","buy","hide","break"]', 1, 'People use the money from their jobs to buy needs and wants.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'A person who delivers letters and packages to homes is a ___.', '["mail carrier","teacher","pilot","baker"]', 0, 'A mail carrier''s job is to deliver letters and packages.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'A person who builds houses has the job of a ___.', '["pilot","teacher","builder","baker"]', 2, 'A builder''s job is to build houses and other buildings.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which of these is a WANT and not a need?', '["A video game","Clothes","Water","Food"]', 0, 'A video game is fun to have but is not needed to live.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which group lists only WANTS?', '["Toy, candy, video game","Food, water, clothes","Clothes, candy, water","Water, toy, food"]', 0, 'A toy, candy, and a video game are all fun wants, not needs.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which is a NEED that keeps your body covered and warm?', '["A toy","A balloon","Clothes","A game"]', 2, 'Clothes are a need that keep us warm and covered.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which of these is a WANT, not a need to live?', '["Water to drink","A home to live in","Food to eat","A toy robot"]', 3, 'A toy robot is fun but not needed to live, so it is a want.', 10),
  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which list puts a NEED with a WANT?', '["Toy and game","Game and candy","Food and a toy","Toy and candy"]', 2, 'Food is a need and a toy is a want, so this list has one of each.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which one is a SERVICE someone does for you?', '["A shirt","Fixing a car","A book","A toy car"]', 1, 'Fixing a car is a service because it is work done for someone.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which one is a SERVICE, which is helpful work?', '["A lawn mower","A garden hose","Mowing a lawn","A bag of grass seed"]', 2, 'Mowing a lawn is work done for someone, so it is a service.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Washing someone''s dog for them is a ___.', '["good","toy","service","coin"]', 2, 'Washing a dog is helpful work done for someone, so it is a service.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'Which list has only SERVICES?', '["Haircut, bus ride, checkup","Ball, haircut, checkup","Checkup, book, ball","Apple, bus ride, book"]', 0, 'A haircut, a bus ride, and a checkup are all work done for people.', 10),
  ('economics', '1', 2, 'econ.1.goodsservices', NULL, 'A barber cutting hair is doing work, so a haircut is a ___.', '["need","coin","good","service"]', 3, 'A haircut is work the barber does for you, which is a service.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'How many cents is one nickel worth?', '["5 cents","10 cents","1 cent","25 cents"]', 0, 'A nickel is worth five cents.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'Which coin is worth the LEAST?', '["A dime","A penny","A quarter","A nickel"]', 1, 'A penny is worth one cent, the least of these coins.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'How many cents are in one dollar?', '["10 cents","50 cents","100 cents","25 cents"]', 2, 'One dollar is the same as one hundred cents.', 10),
  ('economics', '1', 2, 'econ.1.money', NULL, 'Two dimes together are worth ___ cents.', '["25 cents","20 cents","10 cents","5 cents"]', 1, 'Each dime is 10 cents, so two dimes are 20 cents.', 10),
  ('economics', '1', 2, 'econ.1.jobs', NULL, 'A person who helps sick people get better has the job of a ___.', '["painter","doctor","baker","pilot"]', 1, 'A doctor''s job is to help people who are sick feel better.', 10),
