  ('science', '2', 2, '2.matter', NULL, 'Which one keeps its own shape?', '["Steam","A liquid","A solid block","A gas"]', 2, 'Solids keep their shape; liquids and gases do not.', 10),
  ('science', '2', 2, '2.matter', NULL, 'When water boils, it turns into steam, which is a ___.', '["liquid forever","gas","rock","solid"]', 1, 'Boiling water makes steam, a gas.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'A butterfly starts its life as an ___.', '["bird","bee","adult butterfly","egg"]', 3, 'A butterfly''s life begins as a tiny egg.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'What does a caterpillar turn into?', '["A frog","A butterfly","A bee","A bird"]', 1, 'A caterpillar changes into a butterfly.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'The butterfly life cycle is: egg, caterpillar, chrysalis, then ___.', '["tadpole","seed","egg again first","butterfly"]', 3, 'After the chrysalis, an adult butterfly comes out.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'A frog begins its life as a ___.', '["seed","chick","puppy","tadpole"]', 3, 'Frogs hatch as tadpoles that swim in water.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'A new plant''s life can start from a ___.', '["seed","rock","cloud","brick"]', 0, 'Many plants start their life cycle as a seed.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'Inside a chrysalis, a caterpillar ___ into a butterfly.', '["turns into a rock","changes","shrinks to nothing","disappears"]', 1, 'The caterpillar''s body changes into a butterfly inside the chrysalis.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'A magnet can pull on objects made of ___.', '["iron or steel","plastic","wood","paper"]', 0, 'Magnets attract metals like iron and steel.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Will a magnet stick to a metal paper clip?', '["No, never","Yes","Only plastic","Only if it is wet"]', 1, 'Metal paper clips are attracted to magnets.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Two magnets can ___ each other.', '["only talk to","push or pull","paint","eat"]', 1, 'Magnets can attract (pull) or repel (push) each other.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'A magnet will NOT pick up a ___.', '["plastic toy","iron paper clip","steel nail","metal key"]', 0, 'Magnets do not stick to plastic.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'The two ends of a magnet are called its ___.', '["tails","poles","wings","wheels"]', 1, 'A magnet has a north pole and a south pole.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'A magnet can attract a paper clip through ___.', '["a thin sheet of paper","a thick steel door","nothing at all","solid rock"]', 0, 'Magnet force can work through thin things like paper.', 10),
  ('science', '2', 2, '2.weather', NULL, 'We measure how hot or cold it is with a ___.', '["thermometer","clock","ruler","scale"]', 0, 'A thermometer measures temperature.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Strong moving air is called ___.', '["sunshine","snow","wind","rain"]', 2, 'Wind is air that is moving.', 10),
  ('science', '2', 2, '2.weather', NULL, 'A tool that shows which way the wind is blowing is a ___.', '["scale","thermometer","ruler","weather vane"]', 3, 'A weather vane points in the direction the wind comes from.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Which season often brings snow in cold places?', '["None","Summer","Spring","Winter"]', 3, 'Snow usually falls in winter.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Many dark clouds in the sky may mean ___ is coming.', '["rain","only sunshine","nothing","snow in summer"]', 0, 'Dark, heavy clouds often bring rain.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Weather can change from ___.', '["only at night","only once a year","day to day","never"]', 2, 'Weather changes often, even day to day.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A habitat is a place where an animal ___.', '["watches TV","lives","goes to school","buys food"]', 1, 'A habitat is an animal''s home, where it lives.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A fish''s habitat is the ___.', '["snow","desert sand","water","treetop"]', 2, 'Fish live in water.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A camel is well suited to live in the hot, dry ___.', '["ice cap","ocean","forest pond","desert"]', 3, 'Camels can live in the dry desert.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A polar bear lives where it is very ___.', '["sandy","hot","cold","dry"]', 2, 'Polar bears live in cold, icy places.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A habitat gives animals food, water, and ___.', '["money","shelter","toys","homework"]', 1, 'A good habitat provides food, water, and shelter.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which animal lives in a forest habitat?', '["A dolphin","A deer","A whale","A shark"]', 1, 'Deer live in forests; sharks and whales live in the ocean.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which is a liquid?', '["A chair","A brick","Milk","A rock"]', 2, 'Milk pours and takes the shape of its container — it is a liquid.', 10),
  ('science', '2', 2, '2.matter', NULL, 'When water freezes, it becomes a ___.', '["liquid","gas","solid","cloud"]', 2, 'Frozen water is ice, which is a solid.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'A butterfly hatches from an egg as a ___.', '["bird","frog","caterpillar","butterfly"]', 2, 'The egg hatches into a caterpillar before it becomes a butterfly.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Which material will a magnet pull on?', '["A steel paperclip","A plastic cup","A paper sheet","A wooden block"]', 0, 'Magnets attract iron and steel, not plastic, paper, or wood.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'When you bring two magnets together, they can attract or ___.', '["grow","disappear","melt","repel"]', 3, 'Magnets can pull together (attract) or push apart (repel).', 10),
  ('science', '2', 2, '2.weather', NULL, 'Which tool measures how hot or cold it is?', '["A scale","A ruler","A clock","A thermometer"]', 3, 'A thermometer measures temperature.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A camel is well suited to live in the ___.', '["ice cap","desert","ocean","deep cave"]', 1, 'Camels are adapted to hot, dry deserts.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A fish''s habitat is the ___.', '["desert","water","treetop","sky"]', 1, 'Fish live in water, their habitat.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A habitat that is very hot and dry with lots of sand is called a ___.', '["desert","pond","ocean","forest"]', 0, 'A desert is a hot, dry place covered with sand and very little water.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A squirrel often makes its home in a ___.', '["river","cave underwater","tree","cloud"]', 2, 'Squirrels build nests in trees where they are safe and can find nuts to eat.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A duck''s webbed feet help it move well in its ___ habitat.', '["sky only","cave","water","desert"]', 2, 'A duck''s webbed feet act like paddles to help it swim in water.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which living thing would you most likely find in a forest habitat?', '["deer","shark","camel","jellyfish"]', 0, 'Deer live in forests where there are trees, leaves, and grass to eat.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Plants in a desert habitat must be able to live with very little ___.', '["water","heat","sand","sunlight"]', 0, 'Desert plants survive with very little water because deserts get almost no rain.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'What comes out of a chicken egg when it hatches?', '["a tadpole","a chick","a seed","a caterpillar"]', 1, 'A baby chicken, called a chick, hatches out of a chicken egg.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'What is the very first stage in the life cycle of most plants?', '["a leaf","a flower","a seed","a fruit"]', 2, 'Most plants begin their life cycle as a seed.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'Some baby animals, like a baby insect called a nymph, look ___ their parents.', '["colder than","bigger than","nothing like","a lot like"]', 3, 'A nymph looks a lot like its parents, just smaller.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'A grown-up frog lives mostly ___, but it began life in the water.', '["only in the desert","on land and in water","under the snow","in the clouds"]', 1, 'Adult frogs can live both on land and in water, but they start life as tadpoles in water.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Which object would a magnet pull toward it?', '["a plastic spoon","a paper cup","a wooden block","an iron nail"]', 3, 'A magnet pulls on objects made of iron, like an iron nail.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'A magnet can pull on a paper clip even through a thin sheet of ___.', '["thick iron","another magnet","paper","stone"]', 2, 'A magnet''s pull can pass through thin materials like paper to reach a paper clip.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'If you cover a magnet with a paper towel, will it still pick up a small steel pin?', '["no, paper stops all magnets","only if the towel is wet","only at night","yes, the pull goes through the towel"]', 3, 'A magnet''s pull can pass through a thin paper towel to reach the steel pin.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Why does a magnet NOT pick up a penny made of copper?', '["copper is not pulled by magnets","pennies are too small","copper is alive","pennies are too heavy"]', 0, 'Magnets only pull iron and a few other metals, not copper.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Which of these is true about a magnet?', '["it must be hot to work","it can pull on every object","it can pull on iron without touching it","it only works underwater"]', 2, 'A magnet can attract iron objects from a short distance without touching them.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which of these is a solid?', '["a wooden block","air","milk","steam"]', 0, 'A wooden block is a solid because it keeps its own shape.', 10),
  ('science', '2', 2, '2.matter', NULL, 'When you blow up a balloon, you fill it with a ___.', '["liquid metal","gas","rock","solid"]', 1, 'A blown-up balloon is filled with air, which is a gas.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Cutting a piece of paper into smaller pieces changes its ___.', '["shape","material","color","weight a lot"]', 0, 'Cutting paper changes its shape, but it is still paper.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which tool would you use to measure how much a small object weighs?', '["a magnet","a clock","a ruler","a scale"]', 3, 'A scale measures how much an object weighs.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which property of matter tells you if something feels rough or smooth?', '["sound","weight","texture","color"]', 2, 'Texture is the property that tells how something feels, like rough or smooth.', 10),
  ('science', '2', 2, '2.weather', NULL, 'A day with no clouds and bright sun is called a ___ day.', '["rainy","foggy","snowy","sunny"]', 3, 'A sunny day has bright sun and few or no clouds.', 10),
  ('science', '2', 2, '2.weather', NULL, 'What do we call the loud sound that comes after lightning?', '["thunder","wind","fog","rain"]', 0, 'Thunder is the loud sound that follows a lightning flash.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Which season is usually the warmest where you live?', '["early spring","fall","winter","summer"]', 3, 'Summer is usually the warmest season of the year.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Tiny drops of water that form on cool grass in the morning are called ___.', '["snow","dew","fog","hail"]', 1, 'Dew is small drops of water that form on cool surfaces like grass in the morning.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Which tool would tell you which way the wind is blowing?', '["a rain gauge","a thermometer","a magnet","a weather vane"]', 3, 'A weather vane turns to show the direction the wind is blowing.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which animal is most likely to live in a pond habitat?', '["frog","camel","lion","penguin"]', 0, 'Frogs live in and near ponds where there is water and insects to eat.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Why do many animals live in a rainforest?', '["it has plenty of food and water","it is always cold and dry","there is no rain there","there are no plants there"]', 0, 'A rainforest gives animals lots of food, water, and plants to live among.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which animal is best suited to a cold, snowy habitat?', '["arctic fox","parrot","earthworm","sea turtle"]', 0, 'An arctic fox has thick fur that keeps it warm in cold, snowy places.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A bee gets food from flowers, so a garden full of flowers is a good ___ for it.', '["rock","cloud","habitat","ocean"]', 2, 'A habitat is a place that gives an animal what it needs, and a flower garden gives a bee food.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A spider often builds a ___ to catch its food in its habitat.', '["web","dam","nest of mud","shell"]', 0, 'A spider spins a web to trap insects for food.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'A young plant that has just sprouted from a seed is called a ___.', '["fruit","flower","seedling","root only"]', 2, 'A seedling is a young plant that has just grown out of a seed.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'What is the correct order of a butterfly''s life cycle?', '["caterpillar, egg, butterfly, chrysalis","chrysalis, butterfly, egg, caterpillar","butterfly, egg, caterpillar, chrysalis","egg, caterpillar, chrysalis, butterfly"]', 3, 'A butterfly goes from egg to caterpillar to chrysalis and finally to butterfly.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'Inside a seed there is a tiny ___ that can grow into a new plant.', '["seed of metal","stone","drop of water","baby plant"]', 3, 'A seed holds a tiny baby plant that grows when it gets water and warmth.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'The places on a magnet where its pull is strongest are called the ___.', '["poles","sides","corners","edges"]', 0, 'A magnet''s pull is strongest at its two ends, which are called the poles.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'What do we call it when a magnet pulls an object toward itself?', '["repel","melt","float","attract"]', 3, 'To attract means to pull toward, which is what a magnet does to iron objects.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Every magnet has how many poles?', '["ten","one","two","four"]', 2, 'Every magnet has two poles, often called north and south.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'A toy train that sticks together at the ends most likely uses ___.', '["water","glue that never dries","light","magnets"]', 3, 'Many toy trains use magnets so the cars attract and hold together.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'If a magnet sticks to your refrigerator door, the door must contain ___.', '["only plastic","only wood","only glass","iron or steel"]', 3, 'A magnet sticks to a refrigerator door because the door contains iron or steel.', 10),
  ('science', '2', 2, '2.matter', NULL, 'What is everything around us that takes up space and has weight called?', '["shadow","matter","light","sound"]', 1, 'Matter is anything that takes up space and has weight.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which of these can you NOT usually see but can feel when it moves?', '["a gas like air","a glass of juice","an ice cube","a wooden chair"]', 0, 'Air is a gas you usually cannot see, but you can feel it when it moves as wind.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which property could you use to sort objects?', '["the day of the week","their favorite food","color","their name"]', 2, 'Color is a property of matter you can use to sort objects.', 10),
  ('science', '2', 2, '2.matter', NULL, 'A rock is hard, but a sponge is ___.', '["a liquid","a gas","invisible","soft"]', 3, 'Hard and soft are properties of matter, and a sponge is soft.', 10),
  ('science', '2', 2, '2.matter', NULL, 'A bottle of water that is half full has the water taking the shape of the ___.', '["sky","bottle","air","table"]', 1, 'Water is a liquid, so it takes the shape of the bottle that holds it.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Which tool measures how much rain has fallen?', '["a rain gauge","a thermometer","a clock","a ruler for height"]', 0, 'A rain gauge collects and measures how much rain falls.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Which kind of weather would make a kite fly best?', '["very foggy","calm and still","windy","snowing with no wind"]', 2, 'Wind is needed to lift and fly a kite, so windy weather is best.', 10),
  ('science', '2', 2, '2.weather', NULL, 'What should you wear on a rainy day to stay dry?', '["sunglasses only","a raincoat","sandals only","a swimsuit"]', 1, 'A raincoat keeps you dry by blocking the rain.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Which of these is a type of weather, not a season?', '["winter","fall","summer","rainy"]', 3, 'Rainy describes the weather right now, while summer, winter, and fall are seasons.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Balls of ice that sometimes fall from storm clouds are called ___.', '["fog","frost","dew","hail"]', 3, 'Hail is small balls of ice that can fall from strong storm clouds.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A worm spends most of its life living in the ___.', '["clouds","ocean","soil","tree tops"]', 2, 'Worms live in the soil, where they move through the dirt and eat tiny bits of plants.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which of these is a place where many ocean animals find food and shelter?', '["a hot oven","a coral reef","a snowbank","a desert sand dune"]', 1, 'A coral reef is an ocean habitat where many fish find food and places to hide.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Grasslands are wide open habitats covered mostly with ___.', '["ice","sand only","grass","tall trees"]', 2, 'Grasslands are habitats filled with grass and few trees.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Animals that live in the ocean breathe in different ways, but fish use their ___.', '["gills","ears","roots","fur"]', 0, 'Fish use gills to take in oxygen from the water in their ocean habitat.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which of these does a habitat give to the animals that live there?', '["shelter","the ability to fly","new colors of fur every day","wheels"]', 0, 'A habitat provides shelter along with food and water that animals need.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'As a tadpole grows into a frog, it first grows ___.', '["wings","legs","fur","feathers"]', 1, 'A tadpole grows legs as it changes into a frog.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'Which animal lays eggs that hatch into babies?', '["a cow","a bird","a cat","a dog"]', 1, 'Birds lay eggs, and their babies hatch from those eggs.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'When an animal has babies, we say the animal can ___.', '["float","freeze","reproduce","melt"]', 2, 'Reproduce means to make babies, which all living things can do.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'When a plant grows up, it can make flowers and then new ___.', '["fur","seeds","feathers","scales"]', 1, 'A grown plant makes flowers, which then make new seeds to start the cycle again.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'What will happen if you put two magnets together with their like poles facing each other?', '["they make a sound","they turn into one","they melt","they push apart"]', 3, 'Like poles of two magnets repel, or push away from, each other.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'What do we call it when two magnets push away from each other?', '["repel","melt","attract","stick"]', 0, 'To repel means to push away, which happens when like poles of magnets meet.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Which pair of objects would a magnet pull together?', '["a magnet and an iron key","a magnet and a glass marble","a magnet and a cotton ball","a magnet and a leaf"]', 0, 'A magnet attracts iron objects like an iron key.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Which of these could you use a magnet to find in a pile of sand?', '["wooden chips","glass beads","iron nails","plastic beads"]', 2, 'A magnet can pull iron nails out of sand because it attracts iron.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'What happens to a steel paper clip after it touches a strong magnet for a while?', '["it changes color","it gets much heavier","it can act like a weak magnet","it turns to liquid"]', 2, 'A steel paper clip can become a weak magnet after touching a strong magnet.', 10),
  ('science', '2', 2, '2.matter', NULL, 'A liquid takes the shape of ___.', '["its container","nothing at all","the sky","only a square"]', 0, 'A liquid flows and takes the shape of whatever container holds it.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which change happens when you melt a solid?', '["it turns into a rock","it disappears forever","it turns into a liquid","it becomes a magnet"]', 2, 'Melting changes a solid into a liquid.', 10),
  ('science', '2', 2, '2.matter', NULL, 'What state of matter has a shape that stays the same when you move it?', '["gas","steam","liquid","solid"]', 3, 'A solid keeps its own shape even when you move it.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which of these is a liquid at room temperature?', '["a brick","honey","a marble","a coin"]', 1, 'Honey is a liquid because it can pour and take the shape of its container.', 10),
  ('science', '2', 2, '2.matter', NULL, 'Which of these would you measure with a ruler?', '["how long a pencil is","how hot the soup is","how heavy a rock is","how loud a drum is"]', 0, 'A ruler measures length, such as how long a pencil is.', 10),
  ('science', '2', 2, '2.weather', NULL, 'On a cold winter day, water that falls from clouds may come down as ___.', '["sand","steam","snow","leaves"]', 2, 'When it is very cold, water from clouds freezes and falls as snow.', 10),
  ('science', '2', 2, '2.weather', NULL, 'A rainbow is most likely to appear ___.', '["when the sky has no light","in the middle of the night","after it rains and the sun comes out","when it is snowing"]', 2, 'A rainbow forms when sunlight shines through raindrops after a rain.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Big, dark clouds in the sky often mean a ___ is coming.', '["sunny day","storm","clear night","rainbow"]', 1, 'Dark, heavy clouds often mean rain or a storm is on the way.', 10),
  ('science', '2', 2, '2.weather', NULL, 'On a very hot, sunny day it is smart to ___.', '["wear a heavy coat","drink water and wear a hat","stay under a blanket","play in a thunderstorm"]', 1, 'Drinking water and wearing a hat help keep you cool and safe in hot weather.', 10),
  ('science', '2', 2, '2.weather', NULL, 'Weather can change from one day to the next, so it is ___.', '["not always the same","always the same","only sunny","only at night"]', 0, 'Weather changes from day to day and is not always the same.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which place would be the best habitat for a cactus?', '["a dry desert","a snowy mountain top","a deep lake","the bottom of the sea"]', 0, 'A cactus is suited to live in a dry desert because it can store water and needs very little rain.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'What happens to most animals if their habitat is destroyed?', '["they no longer need water","they turn into plants","they grow much bigger","they may lose their food and home"]', 3, 'When a habitat is destroyed, animals can lose the food, water, and shelter they need.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'A bird''s nest is a place where a bird can ___.', '["lay eggs and raise babies","hide from the sun forever","make its own light","store water for years"]', 0, 'Birds build nests to lay eggs and keep their young safe.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'Which would make a good habitat for a beaver?', '["the inside of a volcano","the top of a tall building","a hot dry desert","a river with trees nearby"]', 3, 'Beavers live near rivers and use trees to build their dams and homes.', 10),
  ('science', '2', 2, '2.habitats', NULL, 'An owl in a forest sleeps during the day and hunts at ___.', '["night","noon","never","sunrise only"]', 0, 'Owls are active at night, when they hunt for mice and other small animals in the forest.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'After a flower is pollinated, it can make ___ that grow into new plants.', '["clouds","feathers","rocks","seeds"]', 3, 'Flowers make seeds, which can grow into new plants.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'What helps a seed start to grow into a plant?', '["wind only","glue and tape","water and warmth","darkness and cold forever"]', 2, 'Seeds need water and warmth to sprout and begin growing.', 10),
  ('science', '2', 2, '2.lifecycle', NULL, 'A caterpillar spends time inside a chrysalis so it can ___.', '["grow fur","lay eggs","turn into a fish","change into a butterfly"]', 3, 'Inside the chrysalis, a caterpillar changes into a butterfly.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Which of these would a magnet NOT stick to?', '["a rubber ball","an iron screw","a metal can with iron","a steel paper clip"]', 0, 'A magnet does not stick to rubber because rubber is not made of iron or steel.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'Which material is best for making a magnet stick?', '["glass","plastic","iron","cloth"]', 2, 'Magnets stick to iron and metals that contain iron.', 10),
  ('science', '2', 2, '2.magnets', NULL, 'The north pole of one magnet and the south pole of another magnet will ___.', '["disappear","make light","push apart","attract each other"]', 3, 'Opposite poles, like north and south, attract and pull together.', 10),
  ('geography', '2', 2, 'geo.2.continents', NULL, 'How many continents are there on Earth?', '["12","7","3","5"]', 1, 'Earth has 7 continents.', 10),
