  ('history', '2', 2, 'hist.2.holidays', NULL, 'Juneteenth is celebrated in which month?', '["June","January","October","March"]', 0, 'Juneteenth is celebrated on June 19 each year.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'Which large bird is a national symbol of the United States?', '["penguin","bald eagle","chicken","ostrich"]', 1, 'The bald eagle is a proud national symbol of the United States.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'Mount Rushmore is a giant carving in the mountain that shows the faces of four ___.', '["presidents","kings","soldiers","explorers"]', 0, 'Mount Rushmore shows the carved faces of four U.S. presidents.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'The Statue of Liberty holds a torch in one hand and a ___ in the other.', '["book","bell","sword","flag"]', 0, 'The Statue of Liberty holds a torch and a tablet, which looks like a book.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'A tall person dressed in red, white, and blue who stands for the United States is called ___.', '["the Tooth Fairy","Jack Frost","Uncle Sam","Santa Claus"]', 2, 'Uncle Sam is a friendly character who stands for the United States.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'Why is the American flag an important symbol?', '["it stands for our whole country","it points the way home","it shows the weather","it tells the time"]', 0, 'The flag is a symbol that stands for the United States and its people.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'The Statue of Liberty wears a crown with pointed spikes that look like ___.', '["feathers","leaves","sun rays","flowers"]', 2, 'The crown on the Statue of Liberty has spikes that look like rays of sunlight.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'St. Augustine, in Florida, is known as the oldest ___ in the United States.', '["river","beach","city","mountain"]', 2, 'St. Augustine, Florida, is the oldest city in the United States.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'Who was the Native American woman who helped guide Lewis and Clark on their journey?', '["Sacagawea","Betsy Ross","Pocahontas","Martha Washington"]', 0, 'Sacagawea helped guide Lewis and Clark across the western land.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'The Pilgrims sailed to America on a ship called the ___.', '["Santa Maria","Titanic","Mayflower","Liberty"]', 2, 'The Pilgrims sailed to America on the ship called the Mayflower.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'Ponce de Leon was an explorer from which country?', '["England","Spain","Canada","France"]', 1, 'Ponce de Leon was a Spanish explorer who came to Florida.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'During the American Revolution, the colonists fought to be free from which country?', '["Italy","England","Japan","Mexico"]', 1, 'The colonists fought the American Revolution to be free from England.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'Florida is a state that was first explored by people from ___.', '["Spain","China","Australia","Egypt"]', 0, 'Spanish explorers were among the first Europeans to come to Florida.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'On Thanksgiving, many families gather to share a big meal and give ___.', '["thanks","candy","presents","fireworks"]', 0, 'Thanksgiving is a day to be thankful and share a meal with family and friends.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'Labor Day is a holiday that honors ___.', '["explorers","soldiers","workers and their hard work","presidents"]', 2, 'Labor Day celebrates workers and all the jobs they do.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'Which holiday celebrates Christopher Columbus sailing across the ocean in 1492?', '["Columbus Day","Labor Day","Memorial Day","Flag Day"]', 0, 'Columbus Day remembers when Columbus sailed across the ocean in 1492.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'On Independence Day, many towns celebrate with parades and ___.', '["fireworks","jack-o-lanterns","Easter eggs","snowmen"]', 0, 'People light fireworks to celebrate the birthday of the United States.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'Presidents who are honored by Americans include George Washington and which other leader on Presidents'' Day?', '["Abraham Lincoln","Paul Revere","Ponce de Leon","Christopher Columbus"]', 0, 'Presidents'' Day honors George Washington and Abraham Lincoln.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'What do many people fly outside their homes on Flag Day and Independence Day?', '["the American flag","a banner for a sale","a kite","a balloon"]', 0, 'People proudly fly the American flag on these patriotic holidays.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'Thanksgiving is celebrated in which month?', '["September","November","February","July"]', 1, 'Thanksgiving is celebrated on the fourth Thursday of November.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'When we say the Pledge of Allegiance, we usually face the ___.', '["clock","flag","door","window"]', 1, 'We face the American flag when we say the Pledge of Allegiance.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'The tall, pointed monument in Washington, D.C. that honors our first president is the ___.', '["Washington Monument","Liberty Bell","Statue of Liberty","Mount Rushmore"]', 0, 'The Washington Monument honors George Washington, our first president.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'The White House and the Capitol are important buildings in which city?', '["Denver","Washington, D.C.","Tampa","Boston"]', 1, 'The White House and the Capitol are both in Washington, D.C.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'Mount Rushmore is carved into a mountain in which kind of place?', '["a desert with no rocks","the rocky hills out west","the ocean","a swamp"]', 1, 'Mount Rushmore is carved into the rocky Black Hills in South Dakota.', 10),
  ('history', '2', 2, 'hist.2.symbols', NULL, 'Which of these is a symbol of the United States?', '["a backpack","the bald eagle","a soccer ball","a pencil"]', 1, 'The bald eagle is a national symbol of the United States.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'Which explorer gave Florida its name long ago?', '["George Washington","Christopher Columbus","Meriwether Lewis","Ponce de Leon"]', 3, 'The Spanish explorer Ponce de Leon named Florida when he arrived in 1513.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'Who led an exploring trip across the western United States with Meriwether Lewis?', '["Uncle Sam","William Clark","Ponce de Leon","Paul Revere"]', 1, 'Lewis and Clark explored the western United States together.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'Thomas Jefferson helped write the famous paper called the ___.', '["grocery list","weather report","Declaration of Independence","telephone book"]', 2, 'Thomas Jefferson helped write the Declaration of Independence.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'What was the job of an explorer like Christopher Columbus?', '["to travel to new places","to bake bread","to teach school","to drive a bus"]', 0, 'Explorers travel to find and learn about new places.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'Abraham Lincoln was the president during the United States ___ War.', '["Space","Civil","Sports","Cold"]', 1, 'Abraham Lincoln was president during the Civil War.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'What do we call a person who travels to learn about new and unknown places?', '["a singer","an explorer","a farmer","a baker"]', 1, 'An explorer is someone who travels to discover new places.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'Flag Day is a special day to celebrate the United States ___.', '["capital","money","anthem","flag"]', 3, 'Flag Day honors the American flag and what it stands for.', 10),
  ('history', '2', 2, 'hist.2.holidays', NULL, 'Many holidays like Memorial Day and Veterans Day help us ___ people who served our country.', '["hide","forget","tease","honor"]', 3, 'These holidays help us honor and thank people who served the country.', 10),
  ('history', '2', 2, 'hist.2.figures', NULL, 'The Pilgrims came to America looking for the freedom to ___.', '["drive fast cars","watch movies","play video games","practice their religion"]', 3, 'The Pilgrims came to America for the freedom to practice their religion.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'What is government?', '["A kind of weather","A board game","A group of people who make laws and lead","A type of food"]', 2, 'Government is the group of people who make laws and lead a community or country.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Who is the leader of the whole United States?', '["The principal","The coach","The president","The mayor"]', 2, 'The president leads the United States.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'What is the capital city of the United States?', '["Orlando","Washington, D.C.","New York City","Los Angeles"]', 1, 'Washington, D.C., is the capital of the United States.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Voting is how citizens ___.', '["buy groceries","ride bikes","choose their leaders","do homework"]', 2, 'Voting lets citizens choose who will lead.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'When a class votes and most people pick the same choice, that choice wins by ___.', '["luck","majority","guessing","magic"]', 1, 'The choice with the most votes (the majority) wins.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Following laws and helping others are a citizen''s ___.', '["vacations","snacks","toys","responsibilities"]', 3, 'Responsibilities are the things good citizens are expected to do.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'One important job of government is to ___.', '["win soccer games","make laws and keep people safe","paint houses","sell candy"]', 1, 'Governments make laws and help keep people safe.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Before voting for a leader, it is smart to ___.', '["guess quickly","learn about the choices","close your eyes","ask no questions"]', 1, 'Good voters learn about the choices before deciding.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Telling the truth and being fair are signs of good ___.', '["character","weather","scenery","luck"]', 0, 'Honesty and fairness show good character — important for citizens.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The three parts, or branches, of the United States government are the legislative, executive, and ___.', '["music branch","shopping branch","judicial branch","weather branch"]', 2, 'The three branches are legislative, executive, and judicial.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The group of people who make laws for the whole United States is called ___.', '["the team","Congress","the band","the class"]', 1, 'Congress is the part of government that makes laws for the country.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'A community helper who puts out fires and helps in emergencies is a ___.', '["gardener","cashier","tailor","firefighter"]', 3, 'Firefighters put out fires and help keep people safe.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The President of the United States works in a famous building called the ___.', '["Doll House","Bird House","Tree House","White House"]', 3, 'The President lives and works in the White House.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Which leader works for the whole country, not just one city?', '["The store manager","The school crossing guard","The President","The mayor"]', 2, 'The President leads the whole United States.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'A judge works in a place called a ___.', '["barn","kitchen","court","garage"]', 2, 'Judges do their work in a court.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'A responsibility is a job or duty that you ___.', '["are supposed to take care of","can give to a pet","get to skip","never have to do"]', 0, 'A responsibility is something you are supposed to take care of.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'A right is something you are free to do or have. Which of these is a right that people in the United States have?', '["The right to speak freely","The right to break rules","The right to take others'' things","The right to skip all chores"]', 0, 'People have the right to speak freely, which means saying what they think.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Helping to clean up your classroom is an example of a ___.', '["secret","mistake","game","responsibility"]', 3, 'Cleaning up is a responsibility that helps everyone.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Being honest means that you ___.', '["take things","tell lies","keep secrets from helpers","tell the truth"]', 3, 'Honesty means telling the truth.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'When you make a mistake, the responsible thing to do is to ___.', '["hide and say nothing","say sorry and try to fix it","get angry","blame someone else"]', 1, 'Taking responsibility means saying sorry and trying to make it right.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Which of these is a responsibility of a student at school?', '["Talking during a test","Following the classroom rules","Running in the hallways","Taking other kids'' lunches"]', 1, 'Following classroom rules is a student''s responsibility.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Taking care of pets by feeding and walking them is a kind of ___.', '["accident","vacation","game","responsibility"]', 3, 'Caring for a pet is a responsibility.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Voting is a way for people to ___.', '["make a choice together","fly a kite","cook dinner","build a house"]', 0, 'Voting lets a group make a choice together.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'What is the fairest way for a class to choose one game to play at recess?', '["Vote and pick the game with the most votes","Pick whoever pushes first","Choose without asking anyone","Let the loudest kid decide"]', 0, 'Voting is a fair way to make a group choice.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'In a fair vote, each person usually gets ___.', '["ten votes","no vote","one vote","a vote only if they are tallest"]', 2, 'In a fair vote, each person gets one vote.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'A paper or screen that people use to mark their votes is called a ___.', '["basket","ballet","ballot","balloon"]', 2, 'A ballot is what voters use to mark their choices.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'If your choice does not win the class vote, the good-citizen thing to do is to ___.', '["accept the result kindly","quit the class","cry and yell at everyone","tear up the votes"]', 0, 'Good citizens accept the results of a fair vote.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Why should each person make their own choice when they vote?', '["So the vote shows what people really think","So no one is happy","So the vote takes longer","So everyone copies one person"]', 0, 'When people vote their own choice, the vote shows what the group really thinks.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Keeping your vote secret means you do not have to ___.', '["vote at all","mark a ballot","tell others who you picked","stand in line"]', 2, 'A secret vote means you can keep your choice private.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The leader who is in charge of a state is the ___.', '["principal","governor","coach","mail carrier"]', 1, 'A governor is the leader of a state.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The special plan that tells how the United States government works is called the ___.', '["Constitution","weather map","menu","grocery list"]', 0, 'The Constitution is the plan, or set of rules, for our government.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Which level of government takes care of your city or town?', '["Federal government","The ocean","Local government","A pet store"]', 2, 'Local government runs the city or town where you live.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The first President of the United States was ___.', '["Thomas Edison","Abraham Lincoln","George Washington","Albert Einstein"]', 2, 'George Washington was the first President of the United States.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Laws are made so that people can ___.', '["eat only candy","live together safely and fairly","never play games","stay up all night"]', 1, 'Laws help people live together in a safe and fair way.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Which of these is a national symbol of the United States?', '["A pizza","The bald eagle","A bicycle","A pillow"]', 1, 'The bald eagle is a symbol of the United States.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Throwing your trash in a trash can instead of on the ground shows that you are ___.', '["unkind","hungry","responsible","tired"]', 2, 'Putting trash where it belongs is a responsible thing to do.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'A citizen is a member of a ___.', '["country or community","toy store","cartoon show","cereal box"]', 0, 'A citizen is a member of a country or community.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'A good citizen who sees trash on the playground should ___.', '["hide it under a rock","kick it around","leave it there","pick it up and throw it away"]', 3, 'Picking up trash helps keep the community clean.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Which is a responsibility that helps your community?', '["Ignoring people who need help","Volunteering to help others","Making messes in the park","Yelling at neighbors"]', 1, 'Volunteering is a way to help your community.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'People have a right to be safe. Whose job is it to help protect that right?', '["Police officers and other helpers","Only cartoon characters","No one at all","Only babies"]', 0, 'Community helpers like police officers work to keep people safe.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Which of these is a way to be a responsible friend?', '["Keep your promises","Tell secrets to be mean","Break your promises","Ignore your friends"]', 0, 'Keeping promises is part of being a responsible friend.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Telling an adult when someone is being bullied is a responsible way to ___.', '["help keep people safe","start trouble","ignore the problem","be unkind"]', 0, 'Telling an adult helps keep people safe.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'A person who is chosen by voting to lead is called an ___ leader.', '["invisible","elected","unknown","unfair"]', 1, 'An elected leader is chosen by the votes of the people.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Before voting for a leader, it is smart to first ___.', '["close your eyes and guess","ask no one anything","learn about the choices","vote ten times"]', 2, 'Learning about the choices helps you make a good vote.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'The place where grown-ups go to cast their votes is called a ___.', '["swimming pool","polling place","movie theater","candy shop"]', 1, 'A polling place is where people go to vote.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Voting is one important way that citizens can ___.', '["fly to the moon","take part in their government","skip school","grow taller"]', 1, 'Voting is a way citizens take part in their government.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Counting the votes one by one to find the winner is called ___ the votes.', '["tallying","eating","hiding","painting"]', 0, 'Tallying means counting the votes to see which choice won.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Which is a reason it is good to vote when you grow up?', '["You get to skip work forever","You can vote for the sun to shine","You never have to follow laws","You help choose your leaders"]', 3, 'Voting lets grown-ups help choose their leaders.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Which branch of government has the President as its leader?', '["The executive branch","The judicial branch","The legislative branch","The school branch"]', 0, 'The President leads the executive branch, which carries out the laws.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Who is the leader, or governor, in charge of a whole state like Florida?', '["The librarian","The President","The governor","The mayor"]', 2, 'Each state has a governor as its leader.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The Constitution is best described as a set of ___ for the whole country.', '["rules","games","songs","snacks"]', 0, 'The Constitution is the most important set of rules for the United States.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The government that runs the whole United States is called the ___ government.', '["store","city","school","federal"]', 3, 'The federal government is the national government for the whole country.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The flag of the United States has stars that stand for the ___.', '["cars","trees","states","dogs"]', 2, 'Each star on the U.S. flag stands for one of the 50 states.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'What is a law?', '["A board game","A kind of bird","A type of dessert","A rule that everyone in the country must follow"]', 3, 'A law is a rule made by government that everyone must follow.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'A person who leads a whole school is called the ___.', '["captain","principal","senator","governor"]', 1, 'A principal is the leader of a school.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Which choice shows a person taking responsibility at home?', '["Making messes on purpose","Leaving every chore for others","Hiding from all work","Making their bed and helping with dishes"]', 3, 'Helping with chores at home is taking responsibility.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'What should voters do to make a good choice in an election?', '["Pick the name that is longest","Vote for everyone at once","Choose without thinking","Think carefully about the candidates"]', 3, 'Thinking carefully about the candidates helps voters make a good choice.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Which branch of government has judges who decide if laws are fair?', '["The judicial branch","The library branch","The executive branch","The legislative branch"]', 0, 'The judicial branch is made of courts and judges who decide what laws mean.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'The leader in charge of a city or town is called the ___.', '["captain","governor","mayor","President"]', 2, 'A mayor is the leader of a city or town.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'A community helper who works to keep people safe and helps stop crime is a ___.', '["pilot","painter","baker","police officer"]', 3, 'Police officers help keep the community safe.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Which of these is a job that government does for a community?', '["Brushes your teeth","Builds and fixes roads","Picks your favorite color","Bakes everyone''s birthday cake"]', 1, 'Government builds and takes care of roads for everyone.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'How many states are in the United States?', '["5","50","100","12"]', 1, 'The United States has 50 states.', 10),
  ('civics', '2', 2, 'civ.2.government', NULL, 'Who helps people who are sick or hurt at a hospital?', '["A pilot","A farmer","A clown","A doctor or nurse"]', 3, 'Doctors and nurses help people who are sick or hurt.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'When you take turns and share with others, you are being a good ___.', '["citizen","builder","stranger","leader of the country"]', 0, 'Sharing and taking turns are signs of being a good citizen.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'What is a responsible way to act when crossing the street?', '["Walk backward","Look both ways and use the crosswalk","Run without looking","Close your eyes"]', 1, 'Looking both ways and using the crosswalk keeps you safe.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Treating everyone the same and giving each person a fair turn is called being ___.', '["mean","loud","selfish","fair"]', 3, 'Being fair means treating people equally and giving everyone a fair turn.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Caring for the things you borrow and returning them shows you are ___.', '["greedy","forgetful","unkind","trustworthy"]', 3, 'Taking care of borrowed things and returning them shows you can be trusted.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'Being kind to a new student by including them shows good ___.', '["carelessness","citizenship","laziness","selfishness"]', 1, 'Including others is a sign of good citizenship.', 10),
  ('civics', '2', 2, 'civ.2.responsibility', NULL, 'When the class is making rules together, a responsible student will ___.', '["make fun of others'' ideas","listen and share ideas politely","refuse to talk and pout","shout over everyone"]', 1, 'Sharing ideas politely is a responsible way to help make rules.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'When people vote for the President, they are taking part in an ___.', '["airplane","apple","alphabet","election"]', 3, 'An election is when people vote to choose a leader.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Why is voting important in a community?', '["It lets everyone have a say in decisions","It cleans the streets","It makes the day longer","It picks the weather"]', 0, 'Voting gives everyone a chance to share their choice.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'Which of these is a fair rule for a class vote?', '["Everyone gets to vote","Tall kids vote first and others wait","You must vote twice","Only the teacher''s friends vote"]', 0, 'A fair rule lets everyone in the group vote.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'What do we call the people who run for a job and hope to be voted in?', '["clouds","calendars","candidates","crayons"]', 2, 'Candidates are the people who run to be chosen in an election.', 10),
  ('civics', '2', 2, 'civ.2.voting', NULL, 'A class wants to pick a class pet. The most fair way to decide is to ___.', '["ask a stranger","have everyone vote","flip the desks over","let one person pick for all"]', 1, 'Letting everyone vote is the fair way to choose.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which one is a SERVICE?', '["A teacher teaching a class","A bag of apples","A pair of shoes","A bicycle"]', 0, 'Teaching is a service — helpful work. The others are goods.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A doctor giving a checkup is an example of a ___.', '["good","coin","service","toy"]', 2, 'A checkup is a service the doctor provides.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Putting money away to use later is called ___.', '["losing","eating","spending","saving"]', 3, 'Saving means keeping money to use in the future.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'If you want to buy something that costs more than you have, you should ___.', '["give up forever","take it for free","throw your money away","save up over time"]', 3, 'Saving a little at a time helps you afford bigger things.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'How many cents is one dollar?', '["10","1000","50","100"]', 3, 'One dollar equals 100 cents.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'How much is a quarter worth?', '["1 cent","5 cents","25 cents","10 cents"]', 2, 'A quarter is worth 25 cents.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'Which coin is worth the most?', '["A quarter","A nickel","A penny","A dime"]', 0, 'A quarter (25¢) is worth more than a dime, nickel, or penny.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Trading one thing for another without using money is called ___.', '["earning","borrowing","saving","bartering"]', 3, 'Bartering means swapping goods or services without money.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'How many quarters make one dollar?', '["2","4","10","100"]', 1, 'Four quarters (4 × 25¢) equal 100¢, which is one dollar.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'A good place to keep money you are saving is a ___.', '["puddle","sandbox","trash can","piggy bank or bank"]', 3, 'A piggy bank or a real bank keeps saved money safe.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Buying a toy at a store is buying a ___.', '["service","tax","vote","good"]', 3, 'A toy is a good — an object you can hold and own.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which of these is a GOOD?', '["A bus ride","A dog walk","An apple you can eat","A haircut"]', 2, 'A good is an object you can touch and use, like an apple.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which of these is a service a dentist gives?', '["Baking a cookie","Cleaning your teeth","Selling a toothbrush","Painting a wall"]', 1, 'Cleaning teeth is helpful work, which makes it a service.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A bus driver driving people to school is giving a ___.', '["service","seed","coin","good"]', 0, 'Driving people where they need to go is helpful work, a service.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which of these is a want?', '["Water to drink","A trip to an amusement park","A coat in winter","Food to eat"]', 1, 'A trip to a park is fun but not needed to live, so it is a want.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'How many cents is a dime worth?', '["10 cents","1 cent","5 cents","25 cents"]', 0, 'A dime is worth 10 cents.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'Before money was invented, people often got things by ___.', '["trading goods for goods","using credit cards","using quarters","using dollar bills"]', 0, 'Long ago people traded one good for another instead of using money.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'You buy a snack and the cashier adds a few cents of ___ to the price.', '["candy","glue","fruit","tax"]', 3, 'A sales tax is a small amount added to the price of many things you buy.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Keeping some of your money to use later instead of spending it now is called ___.', '["losing","saving","running","eating"]', 1, 'Saving means keeping money to use at a later time.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Maria wants a $10 toy but has only $4. The best plan is to ___.', '["throw away her money","take a toy without paying","never get the toy","save until she has enough"]', 3, 'Saving more money is the fair way to reach a goal that costs more.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Sam gets $2 each week. To save faster, he should ___.', '["lose it","give it all away","spend it all on candy","put some of it away each week"]', 3, 'Putting some money away each week helps savings grow.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Which of these is a smart reason to keep money in a bank?', '["It will become a toy","It will grow into a plant","It will be kept safe","It will turn into food"]', 2, 'A bank keeps money safe so it is not lost or stolen.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'A person who works at a bank and helps people with their money is called a ___.', '["bus driver","bank teller","mail carrier","painter"]', 1, 'A bank teller helps people put in and take out money at a bank.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Trading one thing for another thing without using money is called ___.', '["bartering","saving","sleeping","taxing"]', 0, 'Bartering means trading goods or services without money.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'When you buy and eat an apple, you are acting as a ___.', '["coin","season","consumer","producer"]', 2, 'Buying and using the apple makes you a consumer.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Lily has time to do only ONE thing: play outside OR read a book. The choice she gives up is her ___.', '["tax","savings","paycheck","opportunity cost"]', 3, 'The thing you give up when you choose is called the opportunity cost.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Which of these shows bartering?', '["Putting coins in a bank","Swapping a toy car for a toy truck","Paying $2 for a book","Adding tax to a bill"]', 1, 'Swapping one toy for another without money is bartering.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Why can''t everyone always get everything they want?', '["Wants do not exist","There is not enough of everything","Stores are always closed","Money is not real"]', 1, 'Because of scarcity, there is not enough of everything for all wants.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which of these is a SERVICE?', '["A loaf of bread","A pair of shoes","A pencil","A teacher teaching a class"]', 3, 'A service is helpful work that one person does for another.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which of these is a want, not a need?', '["A safe home","A toy robot","Warm clothes","Clean water"]', 1, 'A toy robot is a want because you can live without it.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A job is the work a person does to ___.', '["lose money","skip work","take a nap","earn money"]', 3, 'People do jobs to earn money for the things they need and want.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A hat is a ___.', '["tax","bank","good","service"]', 2, 'A hat is an object you can touch, so it is a good.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which worker makes a good?', '["A doctor giving a checkup","A teacher reading a story","A baker who bakes bread to sell","A coach leading a game"]', 2, 'Bread is an object you can touch, so the baker makes a good.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'How many cents is a nickel worth?', '["10 cents","25 cents","5 cents","1 cent"]', 2, 'A nickel is worth 5 cents.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'How many dimes make one dollar?', '["4 dimes","2 dimes","10 dimes","5 dimes"]', 2, 'A dollar is 100 cents, and 10 dimes equal 100 cents.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'You have two dimes. How many cents do you have?', '["15 cents","25 cents","10 cents","20 cents"]', 3, 'Each dime is 10 cents, and 10 plus 10 equals 20 cents.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'Why is money useful when you go shopping?', '["It can be traded for goods and services","It can be eaten for lunch","It tells the time","It keeps you warm"]', 0, 'Money is useful because people accept it in trade for goods and services.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'How many nickels make one quarter?', '["10 nickels","2 nickels","4 nickels","5 nickels"]', 3, 'A quarter is 25 cents, and five 5-cent nickels make 25 cents.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'A safe place where people keep their money is a ___.', '["bank","forest","park","beach"]', 0, 'A bank is a safe place to keep money.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'If you spend all your money today, how much will you have saved for tomorrow?', '["More than before","All of it","Half of it","None"]', 3, 'Spending everything today leaves nothing saved for tomorrow.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Which choice helps you save money?', '["Buying every toy you see","Throwing coins in the trash","Putting part of your allowance away","Spending money the moment you get it"]', 2, 'Setting part of your allowance aside is a way to save.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'If you want a $6 book and you have $6, you can ___.', '["spend it on something else","keep saving forever","give the money away first","buy the book now"]', 3, 'When you have saved enough, you can buy the thing you wanted.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Ava has $5 saved and adds $2 more. How much has she saved now?', '["$3","$5","$2","$7"]', 3, 'Adding $2 to $5 gives a total of $7 saved.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'A person who makes or grows things to sell is called a ___.', '["season","planet","producer","color"]', 2, 'A producer is someone who makes or grows goods to sell.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Tim trades his sandwich for Joe''s cookies. This trade is an example of ___.', '["bartering","earning a paycheck","saving money","paying tax"]', 0, 'Swapping a sandwich for cookies without money is bartering.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'You spend your only dollar on a toy, so you cannot buy a snack. The snack you gave up is the ___.', '["bank deposit","sales tax","savings goal","opportunity cost"]', 3, 'The snack you gave up to buy the toy is the opportunity cost.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Ben trades two of his marbles for one of Kim''s toy cars. Both children agree to the trade. This is an example of ___.', '["banking","saving","taxing","bartering"]', 3, 'Trading marbles for a toy car without money is bartering.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'A person mowing lawns to earn money is a producer of a ___.', '["service","cloud","tax","coin"]', 0, 'Mowing lawns is helpful work for others, so it is a service the person produces.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A firefighter putting out a fire is providing a ___.', '["toy","service","good","coin"]', 1, 'Putting out a fire is helpful work, so it is a service.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Why do we call shelter a need?', '["It is fun to play with","It is a kind of toy","People need a safe place to live","It tastes good"]', 2, 'Shelter is a need because everyone needs a safe place to live.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which person does a job that gives a service?', '["A grape in a store","A nurse helping a sick patient","A box of crayons","A bottle of juice"]', 1, 'Helping a patient is work done for others, so it is a service.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which of these names a need that keeps you safe and dry?', '["A sticker","A home","A balloon","A puzzle"]', 1, 'A home is a need that keeps people safe and out of bad weather.', 10);
insert into public.questions (subject_id, grade, difficulty, skill, standard, prompt, choices, answer_index, explanation, xp) values
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A plumber fixing a leaky pipe is giving a ___.', '["good","coin","tax","service"]', 3, 'Fixing a pipe is helpful work done for someone, a service.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'Which is worth more, a dime or a nickel?', '["Neither has value","They are equal","A dime","A nickel"]', 2, 'A dime is 10 cents and a nickel is 5 cents, so a dime is worth more.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'Money that people use to buy things is also called ___.', '["weather","music","currency","homework"]', 2, 'Currency is another word for the money people use to buy things.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'Taxes help pay for things that many people share, such as ___.', '["one family''s toys","public schools and roads","one child''s candy","a single person''s shoes"]', 1, 'Taxes pay for shared things like public schools, roads, and parks.', 10),
  ('economics', '2', 2, 'econ.2.money', NULL, 'Paper money in the United States is measured in ___.', '["dollars","gallons","feet","pounds"]', 0, 'In the United States, paper money is counted in dollars.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'A goal you save money to reach, like buying a bike, is called a ___.', '["weather report","savings goal","spelling word","nap time"]', 1, 'A savings goal is something you save money to buy or do.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Money you keep in the bank instead of spending is part of your ___.', '["bedtime","homework","savings","lunch"]', 2, 'The money you keep instead of spending is called your savings.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Saving a little money over many weeks shows that ___.', '["small amounts add up over time","spending is the only choice","saving never helps","money disappears when saved"]', 0, 'Saving small amounts again and again can add up to a larger amount.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Why might saving be hard sometimes?', '["Saving is against the rules","It can be tempting to spend the money now","Money cannot be saved","Banks do not take money"]', 1, 'Saving can be hard because it is tempting to spend money right away.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which worker gives a service?', '["A mail carrier delivering letters","A baker''s finished cake","A toy on a shelf","A farmer''s basket of corn"]', 0, 'Delivering letters is work done for others, which is a service.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A person who makes shoes to sell is making a ___.', '["good","bank","tax","service"]', 0, 'Shoes are objects you can touch, so they are goods.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which of these is a good you can buy at a store?', '["A car wash","A taxi trip","A box of cereal","A piano lesson"]', 2, 'A box of cereal is an object you can touch, so it is a good.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'A barber giving someone a haircut is doing a ___.', '["seed","good","tax","service"]', 3, 'Cutting hair is helpful work done for another person, a service.', 10),
  ('economics', '2', 2, 'econ.2.goodsservices', NULL, 'Which group lists only goods?', '["A haircut, a book, and a ball","A checkup, a ball, and an apple","A bus ride, an apple, and a book","A book, a ball, and an apple"]', 3, 'Books, balls, and apples are all objects you can touch, so they are goods.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'A small container at home for saving coins is often called a ___.', '["mailbox","piggy bank","toy box","lunch box"]', 1, 'A piggy bank is a small container many people use to save coins.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'When you put your money in a bank, the bank keeps it ___.', '["forever lost","in the trash","at the park","safe for you"]', 3, 'A bank keeps your money safe until you need it.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Leo saves $1 each week. After 3 weeks, how much has he saved?', '["$5","$3","$1","$2"]', 1, 'Saving $1 for 3 weeks gives 1 plus 1 plus 1, which is $3.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'Which is the better choice if you want to buy a gift next month?', '["Lose your money on purpose","Save some money now","Throw your money away","Spend all your money today"]', 1, 'Saving now means you will have money for the gift next month.', 10),
  ('economics', '2', 2, 'econ.2.saving', NULL, 'What is the best place to keep a large amount of money safe?', '["On the sidewalk","Hanging from a tree","Under a pile of leaves","A bank"]', 3, 'A bank is the safest of these places to keep a large amount of money.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'A farmer who grows apples to sell is acting as a ___.', '["producer","tax","consumer","bank"]', 0, 'Growing apples to sell makes the farmer a producer.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Scarcity means there is ___ of something to meet everyone''s wants.', '["not enough","plenty","extra","too much"]', 0, 'Scarcity means there is not enough of something for all the people who want it.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'A bakery that makes bread for people to buy is a ___.', '["cloud","river","consumer","producer"]', 3, 'The bakery makes goods to sell, so it is a producer.', 10),
  ('economics', '2', 2, 'econ.2.trade', NULL, 'Choosing one thing always means giving up another. What we give up is called the ___.', '["savings","sales tax","paycheck","opportunity cost"]', 3, 'The thing we give up when we make a choice is the opportunity cost.', 10),
