  ('reading', '3', 2, '3.detail', 'ELA.3.R.2', 'Read: "Penguins are birds, but they cannot fly. Instead, they use their wings to swim fast underwater." How do penguins use their wings?', '["To build nests","To fly high","To swim underwater","To stay warm"]', 2, 'The passage says penguins use their wings to swim fast underwater.', 15),
  ('reading', '3', 2, '3.vocab', 'ELA.3.V.1', 'Read: "The enormous elephant filled the whole tent." In this sentence, "enormous" means:', '["gray","fast","tiny","very big"]', 3, '"Enormous" means very big or huge.', 10),
  ('reading', '3', 2, '3.detail', 'ELA.3.R.2', 'Read: "Maria forgot her umbrella. By the time she got home, she was soaked." What can you tell from this?', '["It was windy only","It was raining","It was sunny","It was snowing"]', 1, 'She got soaked without an umbrella, so it must have been raining.', 15),
  ('science', '3', 2, '3.watercycle', NULL, 'When the sun heats water and it turns into vapor, it is called ___.', '["freezing","evaporation","snowing","raining"]', 1, 'Evaporation is liquid water turning into water vapor.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Water vapor cools high in the sky and forms ___.', '["rocks","wind","sand","clouds"]', 3, 'Cooled water vapor forms clouds.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Water that falls from clouds as rain or snow is called ___.', '["a shadow","precipitation","evaporation","wind"]', 1, 'Rain, snow, and sleet are all precipitation.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'The water cycle is powered by energy from the ___.', '["ground","wind","sun","moon"]', 2, 'The sun''s heat drives the whole water cycle.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'When water vapor cools and turns back into liquid drops, it is ___.', '["condensation","evaporation","freezing","melting"]', 0, 'Condensation is water vapor turning back into liquid.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'After it rains, water collects in ___.', '["the air only","rivers and lakes","the sun","clouds only"]', 1, 'Rain collects in rivers, lakes, and oceans.', 10),
  ('science', '3', 2, '3.energy', NULL, 'The sun gives off light and ___ energy.', '["heat","sound","metal","rock"]', 0, 'The sun gives off light and heat energy.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A drum makes ___ energy when you hit it.', '["sound","rock","ice","light"]', 0, 'Hitting a drum makes it vibrate and create sound energy.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A flashlight gives off ___ energy.', '["light","water","cold","sound only"]', 0, 'A flashlight makes light energy.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Rubbing your hands together quickly makes ___.', '["light","ice","heat","rain"]', 2, 'Rubbing makes friction, which produces heat.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Energy that comes from the sun is called ___ energy.', '["wind","sound","muscle","solar"]', 3, 'Energy from the sun is solar energy.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Which of these uses electrical energy to work?', '["A paper clip","A lamp","A wooden spoon","A rock"]', 1, 'A lamp uses electrical energy to make light.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A force is a push or a ___.', '["color","song","pull","smell"]', 2, 'Forces are pushes and pulls.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Which force pulls objects down toward the Earth?', '["Gravity","Light","Sound","Wind"]', 0, 'Gravity pulls everything toward the Earth.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A force can change an object''s ___.', '["smell","motion","name","color"]', 1, 'Forces can speed up, slow down, or turn objects.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Friction is a force that ___ moving things.', '["feeds","colors","speeds up","slows down"]', 3, 'Friction slows objects as surfaces rub together.', 10),
  ('science', '3', 2, '3.forces', NULL, 'The harder you push a ball, the ___ it goes.', '["quieter","slower","faster","smaller"]', 2, 'A bigger push gives the ball more speed.', 10),
  ('science', '3', 2, '3.forces', NULL, 'When you drop a ball, ___ pulls it to the ground.', '["a magnet","gravity","sound","wind only"]', 1, 'Gravity pulls the dropped ball down.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Heating water enough makes it ___.', '["freeze","boil into steam","turn to rock","disappear forever"]', 1, 'Enough heat makes water boil and become steam.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Cooling water below freezing makes it turn into ___.', '["ice","sand","gas","metal"]', 0, 'Water freezes into solid ice when it gets cold enough.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Melting and freezing are changes you can ___.', '["only do once","reverse","never undo","not see"]', 1, 'You can melt ice and freeze it again — these changes can be reversed.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Which is a property of matter you can measure?', '["Its mood","Its luck","Mass","Its name"]', 2, 'Mass (how much matter) can be measured.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'When you stir sugar into water, the sugar ___.', '["turns into air","becomes a rock","vanishes forever","dissolves"]', 3, 'The sugar dissolves and mixes into the water.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Matter is anything that has mass and takes up ___.', '["sound","light","space","time"]', 2, 'Matter has mass and takes up space.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Soil is made of tiny bits of ___ and rotted plants.', '["rock","glass","plastic","metal"]', 0, 'Soil contains broken-down rock and rotted plant matter.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which is a natural Earth material?', '["A rock","A metal can","A plastic toy","A glass bottle"]', 0, 'Rocks form naturally on Earth.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Worms help make soil ___ for plants.', '["poisonous","dry as dust","healthy","frozen"]', 2, 'Worms loosen soil and add nutrients, helping plants.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'When wind and water slowly break rocks into smaller pieces, it is called ___.', '["melting","weathering","freezing","planting"]', 1, 'Weathering breaks big rocks into smaller pieces over time.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Plants grow best in good ___.', '["plastic","soil","metal","glass"]', 1, 'Healthy soil helps plants grow.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Sand is made of tiny pieces of ___.', '["cloth","rock","wood","candy"]', 1, 'Sand is made of very small bits of rock and shell.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'The sun''s heat turns water into vapor in a step called ___.', '["precipitation","collection","evaporation","condensation"]', 2, 'Evaporation is liquid water becoming vapor.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A glowing light bulb gives off light and ___ energy.', '["heat","magnetic","sound","wind"]', 0, 'Bulbs give off both light and heat energy.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Which force pulls objects down toward the ground?', '["Sound","Gravity","Light","Magnetism"]', 1, 'Gravity pulls things toward Earth.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A force that slows a sliding object by rubbing is ___.', '["sunlight","friction","sound","gravity"]', 1, 'Friction is a rubbing force that slows motion.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Heating ice causes it to ___.', '["freeze","melt","disappear forever","turn to rock"]', 1, 'Heat melts ice back into liquid water.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Wind and water slowly breaking rocks into smaller pieces is called ___.', '["melting","freezing","weathering","growing"]', 2, 'Weathering breaks rock apart over a long time.', 10),
  ('science', '3', 2, '3.energy', NULL, 'What kind of energy lets you hear a bell ringing?', '["Heat energy","Sound energy","Light energy","Chemical energy"]', 1, 'A ringing bell makes vibrations that travel as sound energy to your ears.', 10),
  ('science', '3', 2, '3.energy', NULL, 'When you turn on a flashlight, the battery''s stored energy changes mostly into ___ energy.', '["Magnetic","Wind","Light","Sound"]', 2, 'The battery''s stored energy changes into light energy so the bulb glows.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Which of these is a source of energy that can power a home?', '["An empty box","A wooden chair","A plastic spoon","Sunlight"]', 3, 'Sunlight is an energy source that solar panels can turn into electricity for a home.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Wind turbines spin in the wind to make ___.', '["Rain","Soil","Electricity","Sound only"]', 2, 'Wind pushes the blades around, and the spinning motion is used to make electricity.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A car needs ___ stored in its fuel to make the engine run.', '["Soil","Energy","Magnets","Sound"]', 1, 'Fuel holds stored energy that the engine uses to make the car move.', 10),
  ('science', '3', 2, '3.forces', NULL, 'If you stop pushing a toy car on a smooth floor, it will eventually stop because of ___.', '["Friction","Light","Gravity pushing up","Sound"]', 0, 'Friction between the wheels and floor slowly stops the car.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Which would make a wagon move faster?', '["Pushing it softer","Pushing it harder","Not pushing it","Pulling it backward"]', 1, 'A stronger push gives the wagon more speed.', 10),
  ('science', '3', 2, '3.forces', NULL, 'When you drop a rock and a feather, gravity pulls ___.', '["Both of them down","Neither one","Only the feather down","Only the rock down"]', 0, 'Gravity pulls all objects toward the ground, including rocks and feathers.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Putting oil on a squeaky door hinge makes it move easier by reducing ___.', '["Light","Sound forever","Friction","Gravity"]', 2, 'Oil reduces friction between the moving parts so the hinge turns more easily.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Why do shoes have bumpy bottoms instead of smooth ones?', '["To make light","To make you taller","To reduce gravity","To add friction so you do not slip"]', 3, 'Bumpy soles increase friction with the ground so you grip better.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'When liquid water is left in a freezer, it changes into ice. This is called ___.', '["Burning","Melting","Boiling","Freezing"]', 3, 'Cooling a liquid until it becomes solid is called freezing.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'When you mix sand and water and then pour off the water, you can get the sand back. This means the sand and water made a ___.', '["Solid metal","Mixture","Gas","New substance"]', 1, 'A mixture can be separated again, so sand and water form a mixture.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'When you crush a soda can, you change its ___ but not what it is made of.', '["Material","Name","Shape","Color forever"]', 2, 'Crushing changes the can''s shape, but it is still made of the same metal.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Which tool would you use to measure the mass of an apple?', '["A balance","A clock","A thermometer","A ruler"]', 0, 'A balance is used to measure how much mass an object has.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Iron left out in the rain can turn brown and rust. Rusting is a ___ change.', '["Physical","Freezing","Chemical","Melting"]', 2, 'Rust is a new material, so rusting is a chemical change.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which of these is found in healthy topsoil?', '["Only plastic","Rotted plant and animal bits","Only glass","Only ice"]', 1, 'Healthy topsoil contains rotted plant and animal material that helps plants grow.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which living thing helps make soil better by digging tunnels and mixing it?', '["Eagle","Earthworm","Whale","Goldfish"]', 1, 'Earthworms dig through soil, mixing it and adding air so plants grow better.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Why do many plants grow best in soil with lots of humus?', '["Humus is loud","Humus is shiny","Humus is cold","Humus gives plants nutrients"]', 3, 'Humus adds nutrients that help plants grow strong and healthy.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which property can you use to tell rocks apart?', '["Loudness","Day of the week","Hardness","Its name"]', 2, 'Hardness is a property scientists use to compare and identify rocks.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Why is it hard for many plants to grow in pure sand?', '["Sand does not hold water or nutrients well","Sand is alive","Sand is too colorful","Sand is too loud"]', 0, 'Water drains quickly through sand, so it holds few nutrients for plants.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'In which step of the water cycle do water drops in clouds join together and fall as rain?', '["Condensation","Precipitation","Heating","Evaporation"]', 1, 'Precipitation is when water falls from clouds as rain, snow, sleet, or hail.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'When the air gets very cold, precipitation may fall as ___ instead of rain.', '["Steam","Smoke","Snow","Sand"]', 2, 'When it is cold enough, water freezes and falls as snow.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'The water cycle keeps going around again and again because it is powered by the ___.', '["Soil","Sun","Wind only","Moon"]', 1, 'The sun''s energy drives the water cycle by heating and evaporating water.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Which of these is NOT a form of precipitation?', '["Rain","Snow","Hail","Wind"]', 3, 'Wind is moving air; rain, snow, and hail are forms of precipitation.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Water drops on the outside of a cold glass come from ___ in the air.', '["Rocks","Soil","Light","Water vapor condensing"]', 3, 'Water vapor in the air cools on the cold glass and condenses into drops.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A toaster turns electrical energy mostly into which kind of energy to cook bread?', '["Light energy","Motion energy","Heat energy","Sound energy"]', 2, 'A toaster changes electrical energy into heat energy that warms and browns the bread.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A waterfall has moving water. The moving water has which kind of energy?', '["Motion energy","Magnetic energy","No energy","Sound energy only"]', 0, 'Anything that is moving, like falling water, has motion (kinetic) energy.', 10),
  ('science', '3', 2, '3.energy', NULL, 'When you wind up a toy and let it go, the toy uses ___ energy to move.', '["Stored energy","Sound energy","Heat energy","Light energy"]', 0, 'Winding the toy stores energy in a spring, which is released as motion.', 10),
  ('science', '3', 2, '3.energy', NULL, 'When you rub sandpaper back and forth on wood, the wood gets ___.', '["Colder","Louder","Warmer","Brighter"]', 2, 'Rubbing causes friction, which produces heat energy and warms the wood.', 10),
  ('science', '3', 2, '3.energy', NULL, 'When you clap your hands, you make ___ energy.', '["Light","Sound","Chemical","Magnetic"]', 1, 'Clapping makes the air vibrate, producing sound energy.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A ball rolls farther on smooth ice than on grass because ice has ___ friction.', '["The same","Less","No","More"]', 1, 'Ice is smooth and has less friction, so the ball keeps rolling longer.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Gravity is the force that pulls all objects toward ___.', '["The sky","The sun every night","The wall","The center of the Earth"]', 3, 'Gravity pulls objects down toward the center of the Earth.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Pushing a heavy box takes more force than pushing a light box because the heavy box has more ___.', '["Mass","Color","Light","Sound"]', 0, 'Objects with more mass need a larger force to move them.', 10),
  ('science', '3', 2, '3.forces', NULL, 'When a goalie catches a fast ball, the goalie uses a force to ___ the ball.', '["Make heavier","Stop","Speed up","Change color"]', 1, 'The goalie applies a force that stops the moving ball.', 10),
  ('science', '3', 2, '3.forces', NULL, 'If you push two toy cars with the same force, the lighter car will move ___.', '["Backward","Slower","Not at all","Faster"]', 3, 'With the same force, the lighter car has less mass, so it speeds up more.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Burning a piece of paper makes ash and smoke. This shows a ___ change.', '["Chemical","Physical","Freezing","Melting"]', 0, 'Burning makes new materials like ash and smoke, so it is a chemical change.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Which is a property you can use to describe matter?', '["Color","Loudness only","Day of the week","Its name"]', 0, 'Color is a property of matter you can observe and use to describe an object.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Dissolving salt in warm water makes the salt ___.', '["Seem to disappear into the water","Become a rock","Turn into a gas","Catch fire"]', 0, 'The salt dissolves and spreads through the water so you can no longer see the pieces.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'A puddle slowly dries up in the sun. The water turned into a gas called ___.', '["Water vapor","Ice","Smoke","Dust"]', 0, 'The sun heats the puddle so the water becomes an invisible gas called water vapor.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Which is the best way to separate a mixture of marbles and water?', '["Add more marbles","Burn the marbles","Pour the water through a strainer","Freeze them forever"]', 2, 'A strainer lets the water pass and keeps the marbles, separating the mixture.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Sandy soil feels gritty and lets water drain through it ___.', '["Backward","Only at night","Quickly","Never"]', 2, 'Sandy soil has large grains, so water drains through it quickly.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'The dark, rich part of soil made from rotted plants and animals is called ___.', '["Humus","Pebbles","Glass","Sand"]', 0, 'Humus is the dark material in soil made from rotted plants and animals.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'When river water carries small bits of rock and drops them somewhere new, this is called ___.', '["Deposition","Melting","Freezing","Burning"]', 0, 'Deposition is when moving water drops off the rock and soil it was carrying.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Pebbles are pieces of rock that are ___ than boulders.', '["Warmer","Smaller","Heavier","Louder"]', 1, 'Pebbles are small rocks, much smaller than large boulders.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'A rock that has many tiny holes and feels light is often formed from ___.', '["Plastic","Cooled volcano lava","Ice cubes","Cotton"]', 1, 'Some lightweight, holey rocks form when bubbly lava from a volcano cools.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Dew that forms on grass in the morning is an example of water vapor turning into liquid, called ___.', '["Melting","Evaporation","Freezing","Condensation"]', 3, 'Dew forms when water vapor cools and condenses into liquid drops.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Clouds form when water vapor high in the sky ___.', '["Cools and condenses into tiny drops","Becomes soil","Turns into rock","Heats up and disappears"]', 0, 'Clouds form when rising water vapor cools and condenses into tiny water drops.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Water that soaks down into the ground and is stored under the surface is called ___.', '["Cloud water","Steam","Groundwater","Snow"]', 2, 'Water that sinks into the ground and is stored there is called groundwater.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Why does the same water on Earth get used over and over?', '["New water is made each day","The water cycle recycles it","Water disappears forever","Rocks make new water"]', 1, 'The water cycle moves and recycles Earth''s water so it is used again and again.', 10),
  ('science', '3', 2, '3.energy', NULL, 'What energy does food give your body so you can run and play?', '["Light energy","Magnetic energy","Sound energy","Stored chemical energy"]', 3, 'Food holds stored chemical energy that your body uses to move and grow.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Which object gives off both light and heat at the same time?', '["A magnet","A burning campfire","A rubber ball","A ringing phone"]', 1, 'A campfire produces both light you can see and heat you can feel.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A guitar string makes music because the string is ___.', '["Glowing","Cooling down","Melting","Vibrating"]', 3, 'A plucked string vibrates, and those vibrations make sound energy.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A loud drum can be felt as well as heard because sound is made of ___.', '["Vibrations","Light beams","Magnets","Cold air"]', 0, 'Sound is made of vibrations, which can be both heard and felt.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Which is the best example of using heat energy to help people?', '["Cooking food on a stove","Looking at a picture","Reading a book","Listening to music"]', 0, 'A stove uses heat energy to cook food so it is safe and tasty to eat.', 10),
  ('science', '3', 2, '3.forces', NULL, 'To change the direction a soccer ball is rolling, you must ___ it.', '["Talk to it","Wait without touching it","Apply a force","Look at it"]', 2, 'A push or pull (a force) is needed to change a moving object''s direction.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A magnet pulling on a paper clip without touching it shows that some forces can act ___.', '["Only by touching","Only at night","Only in water","At a distance"]', 3, 'Magnetism is a force that can act on objects from a small distance away.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A force is best described as a ___.', '["Hot or cold feeling","Sound or a smell","Push or a pull","Color or a shape"]', 2, 'A force is any push or pull acting on an object.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A sled goes faster down a steep hill than a gentle hill because gravity pulls it ___.', '["More strongly along the steeper slope","Sideways","Upward","Not at all"]', 0, 'On a steeper slope, more of gravity''s pull speeds the sled along the hill.', 10),
  ('science', '3', 2, '3.forces', NULL, 'A swing slows down and stops over time mostly because of friction and ___.', '["Air resistance","More pushing","Sunlight","Magnets"]', 0, 'Air pushing against the swing and friction slow it until it stops.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Tearing a sheet of paper into pieces is a ___ change because it is still paper.', '["Chemical","Burning","Boiling","Physical"]', 3, 'Tearing changes the shape but not what the paper is made of, so it is a physical change.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'When you cook an egg in a pan, the runny egg becomes solid and cannot turn back. This is a ___ change.', '["Physical","Chemical","Melting","Freezing"]', 1, 'Cooking the egg makes a new material that cannot change back, so it is a chemical change.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Steam on a cold mirror turns into water drops. This is the gas changing into a ___.', '["New gas","Solid","Liquid","Rock"]', 2, 'When the warm steam cools, it changes from a gas into liquid water drops.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Mixing baking soda and vinegar makes bubbles of gas. This is a sign of a ___ change.', '["Physical","Chemical","Melting","Freezing"]', 1, 'Making a new gas is a sign that a chemical change has happened.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'When matter changes from a solid to a liquid by heating, it is called ___.', '["Melting","Burning","Mixing","Freezing"]', 0, 'Heating a solid until it becomes a liquid is called melting.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which type of soil holds the most water and feels sticky when wet?', '["Clay soil","Dry dust","Gravel","Sandy soil"]', 0, 'Clay soil has tiny packed particles that hold water and feel sticky.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which of these is a natural rock?', '["A metal can","A plastic toy","A glass bottle","Granite"]', 3, 'Granite is a hard rock found in nature.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which can break a rock apart over many years by growing into its cracks?', '["A magnet","Sound","Sunlight only","Plant roots"]', 3, 'Plant roots grow into cracks and can slowly push rocks apart.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Plant covering on a hillside helps the soil by ___.', '["Holding the soil in place","Making it rain","Turning soil into rock","Heating the soil"]', 0, 'Plant roots hold soil together so wind and water do not wash it away.', 10),
  ('science', '3', 2, '3.soilrocks', NULL, 'Which of these is the top layer of soil where most plants grow?', '["Solid bedrock","Air","Cloud","Topsoil"]', 3, 'Topsoil is the top layer of soil, rich in nutrients where plants grow.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Where does most of the water that evaporates into the air come from?', '["Oceans, lakes, and rivers","Inside rocks","The moon","Dry sand only"]', 0, 'Most water vapor comes from large bodies of water like oceans, lakes, and rivers.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Plants give off water vapor from their leaves into the air. This step is called ___.', '["Transpiration","Erosion","Burning","Melting"]', 0, 'Transpiration is when plants release water vapor from their leaves.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Fog is best described as a cloud that forms ___.', '["Only on the moon","Close to the ground","Inside rocks","Deep underground"]', 1, 'Fog is a cloud of tiny water drops that forms near the ground.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'Steam rising from a pot of boiling water shows water changing from a liquid to a ___.', '["Cloud of ice","Solid","Rock","Gas"]', 3, 'Boiling water turns into water vapor, which is a gas.', 10),
  ('science', '3', 2, '3.watercycle', NULL, 'In the water cycle, evaporation and condensation are like ___.', '["Both burning","Opposite changes","Exactly the same thing","Both freezing"]', 1, 'Evaporation turns liquid into vapor, while condensation turns vapor back into liquid.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Which of these does NOT use electricity to work?', '["A television","A computer","A candle","A microwave oven"]', 2, 'A candle gives light by burning, not by using electricity.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Solar panels collect energy from the sun to make ___.', '["Sound","Wind","Rocks","Electricity"]', 3, 'Solar panels change the sun''s light energy into electricity.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Which of these gives off heat energy?', '["A hot stove","An ice cube","A cold glass of water","A piece of paper"]', 0, 'A hot stove releases heat energy you can feel from nearby.', 10),
  ('science', '3', 2, '3.energy', NULL, 'Which kind of energy lets a plant make its own food?', '["Light energy from the sun","Wind energy","Magnetic energy","Sound energy"]', 0, 'Plants use light energy from the sun to make food in their leaves.', 10),
  ('science', '3', 2, '3.energy', NULL, 'A lamp that is turned off has no ___ coming from its bulb.', '["Mass","Color","Light energy","Shape"]', 2, 'When a lamp is off, the bulb gives off no light energy.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Two children pull a rope in opposite directions with equal strength. The rope will ___.', '["Move quickly left","Stay in one place","Float up","Move quickly right"]', 1, 'Equal forces in opposite directions cancel out, so the rope does not move.', 10),
  ('science', '3', 2, '3.forces', NULL, 'Which surface would create the MOST friction for a sliding box?', '["Rough carpet","Smooth glass","Polished wood","Wet ice"]', 0, 'Rough surfaces like carpet create the most friction and slow things the most.', 10),
  ('science', '3', 2, '3.forces', NULL, 'What happens to a still soccer ball if no one kicks or touches it?', '["It rolls by itself","It stays still","It bounces high","It flies up"]', 1, 'An object at rest stays at rest until a force acts on it.', 10),
  ('science', '3', 2, '3.forces', NULL, 'When you throw a ball straight up, what force brings it back down?', '["Light","Gravity","Sound","Friction only"]', 1, 'Gravity pulls the ball back down toward the Earth.', 10),
  ('science', '3', 2, '3.matterchange', NULL, 'Which change can you reverse by cooling?', '["Ash becoming wood","An egg becoming uncooked","Burned toast becoming bread","Melted chocolate turning solid again"]', 3, 'Melting and freezing can be reversed, so cooling melted chocolate makes it solid again.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Florida is a peninsula, which means it is surrounded by water on ___.', '["all four sides","three sides","no sides","the top only"]', 1, 'A peninsula has water on three sides; Florida is a peninsula.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Which ocean borders the east coast of Florida?', '["Pacific Ocean","Arctic Ocean","Atlantic Ocean","Indian Ocean"]', 2, 'The Atlantic Ocean is on Florida''s east coast.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'The large body of water on Florida''s west coast is the ___.', '["Great Lakes","Red Sea","Gulf of Mexico","Pacific Ocean"]', 2, 'The Gulf of Mexico is on Florida''s west side.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'The famous wetland in southern Florida is the ___.', '["Grand Canyon","Sahara","Everglades","Rocky Mountains"]', 2, 'The Everglades is a large wetland in south Florida.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'The map tool that helps you measure real distance is the ___.', '["title","color","map scale","border"]', 2, 'A map scale shows how distance on the map matches real distance.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'Lines that cross to help you find places on a map form a ___.', '["river","grid","rainbow","road"]', 1, 'A map grid uses crossing lines to locate places.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'How many states are in the United States?', '["50","25","100","13"]', 0, 'The United States has 50 states.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which country is directly NORTH of the United States?', '["Mexico","Japan","Brazil","Canada"]', 3, 'Canada is the country north of the United States.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which country is directly SOUTH of the United States?', '["China","France","Canada","Mexico"]', 3, 'Mexico is the country south of the United States.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'A large area of flat, open land is a ___.', '["plain","island","peak","canyon"]', 0, 'A plain is a wide, flat stretch of land.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'A deep valley with steep rocky sides, often cut by a river, is a ___.', '["pond","hill","beach","canyon"]', 3, 'A canyon is a deep valley with steep sides.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Florida is located in the ___ part of the United States.', '["far west","northwest","central north","southeast"]', 3, 'Florida is in the southeastern United States.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which of these is a U.S. state?', '["Canada","Europe","California","Mexico"]', 2, 'California is one of the 50 U.S. states.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'A symbol shaped like a tent on a map probably marks a ___.', '["river","library","mountain peak","campground"]', 3, 'Map symbols stand for real places; a tent marks a campground.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'Land that sticks out into the water with water on three sides is a ___.', '["peninsula","valley","plain","canyon"]', 0, 'A peninsula has water on three sides — like Florida.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Which warm, fruity crop is Florida especially famous for growing?', '["Wheat","Potatoes","Apples","Oranges"]', 3, 'Florida''s warm, sunny weather makes it one of the top places for growing oranges.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Which large theme-park city sits in central Florida?', '["Tallahassee","Pensacola","Orlando","Key Largo"]', 2, 'Orlando, in central Florida, is famous for its many theme parks.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Most of Florida''s beaches are made of soft ___.', '["ice","clay rock","sand","gravel"]', 2, 'Florida is known for its sandy beaches along the coast.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Which famous southeastern Florida city is known for its beaches and many visitors?', '["Chicago","Denver","Miami","Seattle"]', 2, 'Miami is a large city on Florida''s southeast coast known for its beaches.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'A wide, flat area of land with few trees is called a ___.', '["cliff","volcano","plain","mountain"]', 2, 'A plain is a large, flat, open piece of land.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'A small, raised piece of land that is lower than a mountain is a ___.', '["ocean","plain","hill","island"]', 2, 'A hill is a raised area of land, but smaller and lower than a mountain.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'Where a river empties into a larger body of water, it may drop sand and dirt to form a ___.', '["glacier","delta","desert","plateau"]', 1, 'A delta is land that builds up where a river meets the sea or a lake.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'A piece of land completely surrounded by water is an ___.', '["isthmus","oasis","island","inlet"]', 2, 'An island has water all the way around it.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'Salty water on Earth''s surface that covers most of the planet is found in the ___.', '["lakes","oceans","rivers","ponds"]', 1, 'Oceans are huge bodies of salty water covering most of Earth.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'What do we call a flat drawing that shows where places are?', '["A map","A diary","A recipe","A clock"]', 0, 'A map is a flat picture that shows where places are located.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'The map tool that helps you figure out real distance, like how far one city is from another, is the ___.', '["scale","title","border","color"]', 0, 'A map scale shows how distance on the map compares to real distance.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'On a map, blue color most often stands for ___.', '["deserts","water","forests","cities"]', 1, 'Mapmakers usually use blue to show water like oceans, lakes, and rivers.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'A small picture on a map that stands for a real thing, like a tree for a forest, is a ___.', '["number","border","sentence","symbol"]', 3, 'A map symbol is a small picture that stands for a real place or thing.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'A map that shows mountains, rivers, and other natural features is called a ___ map.', '["treasure","physical","number","weather"]', 1, 'A physical map shows natural features such as mountains and rivers.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which country borders the United States to the NORTH?', '["Mexico","Canada","Cuba","Brazil"]', 1, 'Canada lies directly north of the United States.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which older mountain range runs along the EASTERN United States?', '["Sierra Nevada","Appalachian Mountains","Cascade Range","Rocky Mountains"]', 1, 'The Appalachian Mountains run along the eastern United States.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which large, cold U.S. state is far to the northwest, separated from the other states by Canada?', '["Georgia","Alaska","Iowa","Florida"]', 1, 'Alaska is the northwestern state, separated from the rest of the U.S. by Canada.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which U.S. state is directly WEST of Florida along the Gulf of Mexico?', '["Alabama","New York","Michigan","Oregon"]', 0, 'Alabama lies just west of Florida along the Gulf coast.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which state, in the southwest, shares a long border with Mexico and is known for being very large?', '["Ohio","Texas","Florida","Maine"]', 1, 'Texas is a large southwestern state that borders Mexico.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Which of these is the largest city in Florida by population?', '["Ocala","Naples","Key West","Jacksonville"]', 3, 'Jacksonville, in northeast Florida, has more people than any other Florida city.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Which large lake in central-south Florida is the biggest lake in the state?', '["Lake Tahoe","Lake Michigan","Lake Erie","Lake Okeechobee"]', 3, 'Lake Okeechobee is the largest freshwater lake in Florida.', 10),
