  ('geography', '3', 2, 'geo.3.landforms', NULL, 'A natural stream of fresh water that flows toward a lake or ocean is a ___.', '["plain","river","island","desert"]', 1, 'A river is moving fresh water that flows across the land.', 10),
  ('geography', '3', 2, 'geo.3.landforms', NULL, 'A long line of mountains that are close together is called a mountain ___.', '["delta","range","plain","valley"]', 1, 'A group of mountains in a row is called a mountain range.', 10),
