  ('geography', '3', 2, 'geo.3.maptools', NULL, 'The four cardinal directions are north, south, east, and ___.', '["up","around","west","middle"]', 2, 'The four cardinal directions are north, south, east, and west.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'A round model of the whole Earth is called a ___.', '["graph","globe","poster","clock"]', 1, 'A globe is a small, round model of the Earth.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'The set of lines that cross to help you find places on a map is a ___.', '["scale","grid","key","title"]', 1, 'A grid is a pattern of crossing lines that helps locate places on a map.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'The compass rose on a map is used to show ___.', '["the time","prices","directions","the weather"]', 2, 'A compass rose shows the directions north, south, east, and west on a map.', 10),
  ('geography', '3', 2, 'geo.3.maptools', NULL, 'A map that shows the borders of states and countries is called a ___ map.', '["star","political","menu","ocean"]', 1, 'A political map shows borders of states, countries, and cities.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'Which country borders the United States to the SOUTH?', '["France","Canada","Mexico","Japan"]', 2, 'Mexico lies directly south of the United States.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'The five large lakes shared by the United States and Canada are called the ___.', '["Great Lakes","Twin Lakes","Salt Lakes","Finger Lakes"]', 0, 'The Great Lakes are five huge lakes between the U.S. and Canada.', 10),
  ('geography', '3', 2, 'geo.3.usregions', NULL, 'The cool, rainy region in the far northwest of the mainland U.S. is the Pacific ___.', '["Northwest","Plains","Islands","Southeast"]', 0, 'The Pacific Northwest is the rainy region in the far northwest of the mainland U.S.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'The chain of small islands stretching south from the tip of Florida is called the ___.', '["Florida Hills","Florida Keys","Florida Panhandle","Florida Plains"]', 1, 'The Florida Keys are a chain of islands reaching out into the ocean south of the mainland.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Because Florida sticks out into the water with ocean on three sides, it is shaped like a ___.', '["canyon","mountain","peninsula","desert"]', 2, 'A peninsula is land with water on three sides, which describes Florida''s shape.', 10),
  ('geography', '3', 2, 'geo.3.florida', NULL, 'Which state is directly NORTH of Florida along its border?', '["Texas","Maine","Georgia","Ohio"]', 2, 'Georgia shares Florida''s northern border.', 10),
