  ('reading', '4', 2, '4.grammar', 'ELA.4.C.3', 'Choose the correct word:  ___ going to the park.', '["They''re","Thier","There","Their"]', 0, 'They are going — the contraction is "They''re".', 15),
  ('reading', '4', 2, '4.grammar', 'ELA.4.C.3', 'Choose the correct word:  The sky is ___.', '["bleu","bloo","blew","blue"]', 3, '"Blue" is the color.', 15),
  ('reading', '4', 2, '4.grammar', 'ELA.4.C.3', 'Choose the correct word:  Put the book over ___.', '["there","they''re","their","thier"]', 0, '"There" tells where — over there.', 15),
  ('reading', '4', 2, '4.grammar', 'ELA.4.C.3', 'Choose the correct word:  The wind ___ all day.', '["bleu","blue","blewe","blew"]', 3, '"Blew" is the past tense of blow.', 15),
