  ('civics', '4', 2, 'civ.4.citizenship', NULL, 'Which of these is a right of citizens in the United States?', '["Freedom of the press","Never doing homework","Always winning a game","Getting a free house"]', 0, 'Freedom of the press lets people share news and ideas freely.', 10),
  ('civics', '4', 2, 'civ.4.citizenship', NULL, 'Freedom of speech means people can ___.', '["never go to court","do anything they want with no rules","share their ideas and opinions","skip paying taxes"]', 2, 'Freedom of speech lets people share their ideas and opinions.', 10),
