  ('civics', '4', 2, 'civ.4.constitution', NULL, 'The Constitution protects freedom of speech in the ___.', '["Bill of Rights","Cabinet","army","Preamble only"]', 0, 'The Bill of Rights protects freedoms such as speech and religion.', 10),
