  ('civics', '4', 2, 'civ.4.stategov', NULL, 'Which level of government is the largest and covers the entire United States?', '["County government","Federal government","City government","Neighborhood government"]', 1, 'The federal government is the largest and covers the whole country.', 10),
  ('civics', '4', 2, 'civ.4.stategov', NULL, 'The President leads which level of government?', '["Federal government","County government","Local government","City government"]', 0, 'The President is the leader of the federal government.', 10),
