  ('civics', '4', 2, 'civ.4.branches', NULL, 'Which branch includes the President and the Cabinet?', '["The judicial branch","The executive branch","The county branch","The legislative branch"]', 1, 'The President and Cabinet are part of the executive branch.', 10),
  ('civics', '4', 2, 'civ.4.citizenship', NULL, 'Which of these is a right protected by the Bill of Rights?', '["Free cars","No school","Freedom of speech","Free ice cream"]', 2, 'Freedom of speech is a right protected by the Bill of Rights.', 10),
