  ('civics', '4', 2, 'civ.4.stategov', NULL, 'Which leader works at the federal level, helping make laws for the whole country?', '["A county commissioner","A school principal","A city mayor","A U.S. senator"]', 3, 'A U.S. senator works at the federal level to help make national laws.', 10),
