  ('civics', '4', 2, 'civ.4.branches', NULL, 'Which of these is a power of the legislative branch?', '["Vetoing a bill","Judging a court case","Leading the navy","Passing a new law"]', 3, 'Passing laws is a job of the legislative branch.', 10),
  ('civics', '4', 2, 'civ.4.branches', NULL, 'Which branch settles disagreements about the law in court?', '["The executive branch","The voting branch","The legislative branch","The judicial branch"]', 3, 'The judicial branch uses courts to settle legal disagreements.', 10),
