  ('civics', '4', 2, 'civ.4.citizenship', NULL, 'A baby born in the United States is a citizen by ___.', '["test","birth","voting","payment"]', 1, 'People born in the United States are citizens by birth.', 10),
  ('civics', '4', 2, 'civ.4.citizenship', NULL, 'People who want to become U.S. citizens usually must pass a ___ test.', '["citizenship","swimming","spelling","driving"]', 0, 'New citizens must pass a citizenship test about U.S. government and history.', 10),
  ('civics', '4', 2, 'civ.4.citizenship', NULL, 'Which is the BEST example of being a responsible citizen at school?', '["Leaving a mess for others","Following the school rules","Ignoring the teacher","Pushing in line"]', 1, 'Following rules at school is a way to practice responsible citizenship.', 10),
  ('civics', '4', 2, 'civ.4.citizenship', NULL, 'Which of these helps make a community a better place to live?', '["Damaging public property","People refusing to help neighbors","Everyone ignoring the rules","Citizens working together to solve problems"]', 3, 'Communities improve when citizens cooperate to solve problems.', 10),
  ('civics', '4', 2, 'civ.4.constitution', NULL, 'The Constitution is often called the highest, or ___, law of the United States.', '["smallest","oldest","weakest","supreme"]', 3, 'The Constitution is the supreme law of the land.', 10),
  ('civics', '4', 2, 'civ.4.constitution', NULL, 'Why did the writers of the Constitution create a written plan of government?', '["So no one could ever read it","So everyone would know the rules for the government","So states would have no power","So only the President could change it"]', 1, 'A written constitution lets everyone know the rules the government must follow.', 10),
  ('civics', '4', 2, 'civ.4.constitution', NULL, 'People who helped write and sign the Constitution are often called the ___.', '["Founding Fathers","Supreme Court","Cabinet","jury"]', 0, 'The Founding Fathers helped write and sign the Constitution.', 10),
  ('economics', '4', 2, 'econ.4.opportunitycost', NULL, 'Opportunity cost is the value of the next-best thing you ___ when you choose.', '["give up","save forever","win","buy twice"]', 0, 'Opportunity cost is the best thing you give up to get what you chose.', 10),
