  ('economics', '4', 2, 'econ.4.budget', NULL, 'A budget is a plan for how to ___ your money.', '["lose","hide and forget","color","earn, spend, and save"]', 3, 'A budget plans how you earn, spend, and save money.', 10),
  ('economics', '4', 2, 'econ.4.budget', NULL, 'Spending less money than you earn lets you ___.', '["run out instantly","owe money","save","go broke"]', 2, 'Spending less than you earn means you can save the rest.', 10),
  ('economics', '4', 2, 'econ.4.supplydemand', NULL, 'When LOTS of people want a toy but there are very few left, the price often goes ___.', '["away","to zero","down","up"]', 3, 'High demand and low supply usually push the price up.', 10),
  ('economics', '4', 2, 'econ.4.supplydemand', NULL, '''Demand'' means how much people ___ to buy something.', '["forget","lose","hate","want"]', 3, 'Demand is how much people want and are willing to buy.', 10),
  ('economics', '4', 2, 'econ.4.business', NULL, 'The money a business has left after paying its costs is called ___.', '["profit","a tax refund","a service","scarcity"]', 0, 'Profit is what''s left after a business pays its costs.', 10),
  ('economics', '4', 2, 'econ.4.budget', NULL, 'In a budget, the money you set aside and do not spend is your ___.', '["scarcity","demand","service","savings"]', 3, 'Money you keep instead of spending is savings.', 10),
