  ('economics', '4', 2, 'econ.4.opportunitycost', NULL, 'You have time to do ONE activity. Choosing to play soccer means the opportunity cost is the ___ you skipped.', '["other activity","weather","soccer ball","calendar"]', 0, 'Opportunity cost is the next-best thing you gave up.', 10),
  ('economics', '4', 2, 'econ.4.budget', NULL, 'A budget is a plan that helps you decide how to ___ the money you have.', '["use","throw away","hide","forget"]', 0, 'A budget is a plan for using your money on saving and spending.', 10),
