  ('reading', '5', 3, '5.infer', 'ELA.5.R.2', 'Read: "Devon checked the sky, grabbed his coat, and tucked an umbrella under his arm before leaving." What can you INFER?', '["He forgot his shoes","He is going to bed","It might rain","It is summer"]', 2, 'The coat and umbrella are clues that Devon expects rain — that is an inference.', 15),
  ('reading', '5', 3, '5.infer', 'ELA.5.R.2', 'Read: "The library was silent except for the soft turn of pages and a distant cough." The mood of this scene is:', '["loud and wild","funny","scary","calm and quiet"]', 3, 'Details like silence and softly turning pages create a calm, quiet mood.', 15),
  ('reading', '5', 3, '5.infer', 'ELA.5.R.2', 'Read: "Scientists studied the coral for years and warned that warmer water harms it." The author wrote this mainly to:', '["inform","entertain","sell something","tell a story"]', 0, 'The passage shares facts and findings, so its purpose is to inform.', 15),
  ('science', '5', 2, '5.solar', NULL, 'What is at the center of our solar system?', '["The Earth","The Sun","The Moon","Jupiter"]', 1, 'The Sun is at the center; the planets orbit it.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which planet do we live on?', '["Mars","Venus","Saturn","Earth"]', 3, 'We live on Earth, the third planet from the Sun.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Planets move around the Sun in paths called ___.', '["orbits","tunnels","shadows","rivers"]', 0, 'An orbit is the path a planet takes around the Sun.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which is the largest planet in our solar system?', '["Earth","Mars","Jupiter","Mercury"]', 2, 'Jupiter is the biggest planet.', 10),
  ('science', '5', 2, '5.solar', NULL, 'The Sun is a ___.', '["star","moon","comet","planet"]', 0, 'The Sun is the star at the center of our solar system.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which planet is known as the ''Red Planet''?', '["Neptune","Mars","Venus","Saturn"]', 1, 'Mars looks reddish, so it''s called the Red Planet.', 10),
  ('science', '5', 2, '5.matter', NULL, 'The tiny particles that make up all matter are too small to ___.', '["see with your eyes","matter","move","be real"]', 0, 'Matter is made of tiny particles far too small to see.', 10),
  ('science', '5', 2, '5.matter', NULL, 'A change where no new substance forms, like melting, is a ___ change.', '["physical","chemical","living","magical"]', 0, 'Melting is a physical change — it''s still the same substance.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Burning wood into ash and smoke is a ___ change.', '["chemical","frozen","physical","reversible"]', 0, 'Burning makes new substances, so it''s a chemical change.', 10),
  ('science', '5', 2, '5.matter', NULL, 'When matter changes state, the amount of matter (its mass) ___.', '["doubles","becomes light","stays the same","disappears"]', 2, 'Mass is conserved — it stays the same when matter changes state.', 10),
  ('science', '5', 2, '5.matter', NULL, 'In which state are the particles packed most tightly?', '["Liquid","Solid","Steam","Gas"]', 1, 'In a solid, particles are packed tightly together.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Mixing things that can be separated again makes a ___.', '["chemical reaction","gas only","brand-new substance forever","mixture"]', 3, 'A mixture can usually be separated back into its parts.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'An object at rest stays at rest unless a ___ acts on it.', '["sound","force","color","shadow"]', 1, 'It takes a force to start a still object moving.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'The force that pulls objects toward the Earth is ___.', '["sound","magnetism only","friction","gravity"]', 3, 'Gravity pulls objects toward Earth.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Which force resists motion when two surfaces rub together?', '["Magnetism","Friction","Gravity","Sound"]', 1, 'Friction acts against motion between rubbing surfaces.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'To make a moving cart speed up, you apply a force in the ___ of motion.', '["color","opposite","direction","sound"]', 2, 'A force in the direction of motion speeds an object up.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'A heavier object needs ___ force to start moving than a lighter one.', '["less","more","no","zero"]', 1, 'More mass needs more force to move.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'A push or pull that can change an object''s speed or direction is a ___.', '["mineral","season","force","habitat"]', 2, 'A force changes how an object moves.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'The original source of energy for almost all food chains is the ___.', '["wind","soil","moon","Sun"]', 3, 'The Sun''s energy starts nearly every food chain.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'Plants that make their own food are called ___.', '["consumers","decomposers","producers","predators"]', 2, 'Producers (plants) make their own food using sunlight.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'An animal that eats only plants is a ___.', '["decomposer","carnivore","herbivore","producer"]', 2, 'Herbivores eat only plants.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'An animal that eats other animals is a ___.', '["plant","herbivore that eats grass","carnivore","producer"]', 2, 'Carnivores eat other animals.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'Which break down dead plants and animals and return nutrients to the soil?', '["The Sun","Decomposers","Herbivores","Producers"]', 1, 'Decomposers, like fungi, recycle nutrients back to the soil.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'In a food chain, energy passes from one living thing to the ___.', '["Sun","next","soil only","air"]', 1, 'Energy moves from one living thing to the next in a food chain.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which organ pumps blood through your body?', '["The heart","The stomach","The lungs","The brain"]', 0, 'The heart pumps blood all around your body.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which organs take in oxygen when you breathe?', '["The kidneys","The lungs","The heart","The liver"]', 1, 'The lungs bring oxygen into your body.', 10),
  ('science', '5', 2, '5.body', NULL, 'The brain is the main organ of the ___ system.', '["nervous","muscular","digestive","skeletal"]', 0, 'The brain and nerves make up the nervous system.', 10),
  ('science', '5', 2, '5.body', NULL, 'Your ___ give your body shape and help it move.', '["fingernails","hair","bones","freckles"]', 2, 'Bones (the skeleton) support and move your body.', 10),
  ('science', '5', 2, '5.body', NULL, 'Food is broken down in your ___ system.', '["nervous","breathing","digestive","skeletal"]', 2, 'The digestive system breaks down food.', 10),
  ('science', '5', 2, '5.body', NULL, 'Blood carries ___ to all parts of your body.', '["only air bubbles","oxygen and nutrients","sound","only water"]', 1, 'Blood delivers oxygen and nutrients to your cells.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'The change from liquid water to water vapor is called ___.', '["condensation","freezing","precipitation","evaporation"]', 3, 'Evaporation turns liquid water into vapor.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'The change from water vapor back to liquid, forming clouds, is ___.', '["evaporation","condensation","precipitation","melting"]', 1, 'Condensation forms cloud droplets from vapor.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Most of Earth''s water is found in the ___.', '["rivers","underground only","oceans","clouds"]', 2, 'Oceans hold most of Earth''s water.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Water that soaks down into the ground becomes ___.', '["a cloud","vapor right away","groundwater","a rock"]', 2, 'Water that sinks into the ground is called groundwater.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'The water cycle recycles Earth''s water over and over, powered by the ___.', '["ground","moon","Sun","wind only"]', 2, 'The Sun''s energy keeps the water cycle going.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Rain, snow, sleet, and hail are all forms of ___.', '["evaporation","groundwater","condensation","precipitation"]', 3, 'All water falling from the sky is precipitation.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which planet do we live on?', '["Mars","Jupiter","Venus","Earth"]', 3, 'Earth is our home planet.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Melting and freezing are examples of a ___ change.', '["magnetic","physical","electric","chemical"]', 1, 'Physical changes keep the same substance; only the state changes.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'To start a still object moving, you must apply a ___.', '["force","color","sound","smell"]', 0, 'A push or pull (a force) changes an object''s motion.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'In a food web, plants are called ___ because they make their own food.', '["predators","decomposers","producers","consumers"]', 2, 'Plants produce their own food using sunlight.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which body system protects your organs and helps you move?', '["The nervous system","The breathing system","The digestive system","The skeletal system"]', 3, 'Bones (the skeletal system) support, protect, and move the body.', 10),
  ('science', '5', 2, '5.solar', NULL, 'How long does it take Earth to make one full trip around the Sun?', '["One day","One week","One year","One month"]', 2, 'Earth completes one orbit around the Sun in about one year.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which planet is closest to the Sun?', '["Venus","Mars","Earth","Mercury"]', 3, 'Mercury is the first planet and the closest one to the Sun.', 10),
  ('science', '5', 2, '5.solar', NULL, 'What is a moon?', '["A natural object that orbits a planet","A burning ball of gas","A piece of the Sun","A small star"]', 0, 'A moon is a natural body that orbits a planet.', 10),
  ('science', '5', 2, '5.solar', NULL, 'What is the asteroid belt?', '["A band of rocky objects between Mars and Jupiter","A group of stars","A ring around Saturn","A path the Moon follows"]', 0, 'The asteroid belt is a region of many rocky objects orbiting the Sun between Mars and Jupiter.', 10),
  ('science', '5', 2, '5.matter', NULL, 'What happens to the volume of a gas when you squeeze it into a smaller space?', '["It stays exactly the same","It gets smaller","It turns into a liquid right away","It disappears"]', 1, 'Gases can be squeezed into a smaller volume because their particles are spread far apart.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which is the best example of dissolving?', '["Rocks placed in a bucket","Sugar mixed into warm water until it disappears","Sand sitting at the bottom of water","Oil floating on top of water"]', 1, 'Sugar dissolves in water, spreading out so evenly that you can no longer see it.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which best describes the particles in a solid?', '["Far apart and moving freely","Packed closely and only vibrating in place","Spread out to fill any space","Not moving at all and disconnected"]', 1, 'In a solid, particles are tightly packed and vibrate in fixed positions.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Why can you pour a liquid but not a solid block of wood?', '["Liquids have no mass","Liquid particles can slide past each other","Solids are heavier than liquids","Liquids are not matter"]', 1, 'Particles in a liquid can move and slide past one another, so liquids can flow and be poured.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which separates a mixture of sand and water?', '["Shaking it harder","Adding sugar","Pouring it through a filter","Heating it until it boils"]', 2, 'A filter traps the sand while letting the water pass through, separating the mixture.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Rubbing your hands together quickly makes them feel warm because of ___.', '["Magnetism","Gravity","Electricity","Friction"]', 3, 'Friction between your moving hands produces heat, warming them up.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Two equal forces pulling an object in opposite directions are called ___ forces.', '["Balanced","Magnetic","Unbalanced","Moving"]', 0, 'Balanced forces are equal in size and opposite in direction, so they cancel out.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Which is an example of a contact force?', '["Gravity pulling an apple down","A magnet attracting a nail nearby","The Sun warming the ground","A hand pushing a door open"]', 3, 'A contact force happens when objects touch, like a hand pushing a door.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'What do we call all the animals that eat other living things for energy?', '["Consumers","Producers","Plants","Decomposers"]', 0, 'Consumers are living things that get energy by eating other organisms.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'What would most likely happen to rabbits if all the foxes that eat them disappeared?', '["The rabbit number would go up","The rabbits would turn into plants","The rabbits would all die","Nothing would change"]', 0, 'With fewer predators eating them, the rabbit population would likely increase.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'An animal that hunts and eats other animals is called a ___.', '["Plant","Prey","Producer","Predator"]', 3, 'A predator is an animal that hunts and eats other animals.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'An owl eats mice. If a disease killed most of the mice, what would happen to the owls?', '["They would not be affected","They would become producers","They would have more food","They would have less food and might decrease"]', 3, 'With fewer mice to eat, the owls would have less food and their numbers could drop.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'A living thing that gets its energy by eating plants is a kind of ___.', '["Consumer","Decomposer","Mineral","Producer"]', 0, 'Anything that eats plants or animals for energy is a consumer.', 10),
  ('science', '5', 2, '5.body', NULL, 'What is the main job of your skeletal system?', '["To pump blood","To support and protect the body","To think and learn","To digest food"]', 1, 'The skeleton gives the body its shape, supports it, and protects organs.', 10),
  ('science', '5', 2, '5.body', NULL, 'Muscles work to move your body by doing which action?', '["Breathing for the lungs","Pulling on bones","Pumping blood by themselves","Making new blood"]', 1, 'Muscles pull on bones to make the body move.', 10),
  ('science', '5', 2, '5.body', NULL, 'What helps protect the soft brain inside your head?', '["The blood","The stomach","The lungs","The skull"]', 3, 'The skull is hard bone that protects the brain.', 10),
  ('science', '5', 2, '5.body', NULL, 'Why does your heart beat faster when you run?', '["To slow your breathing","To cool down your bones","To make you taller","To send more oxygen-rich blood to working muscles"]', 3, 'During exercise, muscles need more oxygen, so the heart beats faster to deliver it.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Tiny drops of water form on the outside of a cold glass on a hot day. This is an example of ___.', '["Evaporation","Condensation","Precipitation","Freezing"]', 1, 'Water vapor in the warm air cools on the glass and condenses into liquid drops.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'How do plants add water vapor to the air?', '["By freezing","By drinking clouds","By making rain","By releasing water from their leaves"]', 3, 'Plants release water vapor into the air through their leaves, adding moisture to the cycle.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'On a cold morning, water vapor in the air freezes onto grass as ___.', '["Frost","Fog","Steam","Rain"]', 0, 'When water vapor freezes onto cold surfaces it forms frost.', 10),
  ('science', '5', 2, '5.solar', NULL, 'What causes day and night on Earth?', '["Earth orbiting the Sun","Earth spinning on its axis","Clouds covering the sky","The Moon blocking the Sun"]', 1, 'As Earth rotates on its axis, one side faces the Sun (day) while the other faces away (night).', 10),
  ('science', '5', 2, '5.solar', NULL, 'What are the four planets closest to the Sun mostly made of?', '["Ice","Gas","Water","Rock"]', 3, 'The four inner planets are rocky planets with solid surfaces.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Why does the Moon shine in the night sky?', '["It reflects light from the Sun","It is on fire","It makes its own light","Stars light it up"]', 0, 'The Moon does not make its own light; it reflects sunlight.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Compared to Earth, the Sun is ___.', '["About the same size","Much smaller","A little larger","Much larger"]', 3, 'The Sun is far larger than Earth; many Earths could fit inside it.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which property describes how much space an object takes up?', '["Color","Volume","Temperature","Mass"]', 1, 'Volume is the amount of space that matter takes up.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which tool would you use to measure the mass of a small rock?', '["A balance","A ruler","A thermometer","A measuring cup"]', 0, 'A balance is used to measure the mass of objects.', 10),
  ('science', '5', 2, '5.matter', NULL, 'You mix salt into water until you cannot see it. How could you get the salt back?', '["Add more water","Let the water evaporate away","Freeze the water","Shake the cup hard"]', 1, 'When the water evaporates, the salt is left behind and can be collected again.', 10),
  ('science', '5', 2, '5.matter', NULL, 'A mixture is different from a chemical change because in a mixture the substances ___.', '["Always change color","Always give off heat","Make a brand-new substance","Can usually be separated again"]', 3, 'In a mixture, the substances keep their properties and can usually be separated.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Which of these is a measure of how fast an object moves?', '["Speed","Color","Mass","Volume"]', 0, 'Speed tells how fast an object is moving.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'A magnet can pull on an object without touching it. This is an example of ___.', '["No force at all","Friction","A force that acts at a distance","A contact force"]', 2, 'Magnetism can act over a distance, pulling on objects without touching them.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'If you stop pedaling a bicycle, why does it slowly stop instead of rolling forever?', '["The wheels get tired","Gravity pushes it backward","It runs out of speed energy","Friction and air slow it down"]', 3, 'Friction from the ground and air resistance gradually slow the bicycle to a stop.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'What is needed to change the direction a moving object is traveling?', '["A force","Bright light","More mass only","Nothing"]', 0, 'A force is required to change an object''s direction of motion.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'An animal that eats both plants and other animals is called a ___.', '["Omnivore","Producer","Herbivore","Carnivore"]', 0, 'An omnivore eats both plants and animals.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'Which group makes its own food using sunlight?', '["Predators","Consumers","Decomposers","Producers"]', 3, 'Producers, like green plants, make their own food using sunlight.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'The animal that gets eaten by a predator is called the ___.', '["Producer","Decomposer","Predator","Prey"]', 3, 'Prey is the animal that a predator hunts and eats.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'A deer that eats only grass and leaves is best called a ___.', '["Carnivore","Decomposer","Herbivore","Omnivore"]', 2, 'A herbivore eats only plants.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which body system carries blood, oxygen, and nutrients all around your body?', '["Nervous system","Digestive system","Skeletal system","Circulatory system"]', 3, 'The circulatory system uses the heart and blood vessels to move blood, oxygen, and nutrients.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which body part sends messages between your brain and the rest of your body?', '["Blood","Bones","Nerves","Skin"]', 2, 'Nerves carry messages between the brain and the rest of the body.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which is the largest organ of the body and helps protect what is inside?', '["The skin","The stomach","The lung","The heart"]', 0, 'The skin is the body''s largest organ and protects the parts inside.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which part of the body holds and mixes food after you swallow it?', '["The heart","The lungs","The stomach","The brain"]', 2, 'The stomach holds and mixes food as part of digestion.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'What is the main source of energy that drives the water cycle?', '["The Moon","The wind only","The soil","The Sun"]', 3, 'The Sun''s heat powers the water cycle by causing evaporation.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'After it rains, puddles slowly dry up in the sunshine. What is happening to the water?', '["It is condensing","It is turning into soil","It is freezing","It is evaporating into the air"]', 3, 'The Sun''s heat turns the puddle water into water vapor through evaporation.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Why is the water cycle important for living things?', '["It makes the Sun shine","It stops the wind","It creates new water that did not exist","It moves fresh water around so plants and animals can use it"]', 3, 'The water cycle keeps fresh water moving so living things can get the water they need.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Which best describes the order of three water cycle steps?', '["Collection, then condensation, then evaporation","Condensation, then precipitation, then evaporation","Evaporation, then condensation, then precipitation","Precipitation, then evaporation, then condensation"]', 2, 'Water evaporates, condenses into clouds, then falls as precipitation.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which object orbits the Earth?', '["Mars","Venus","The Moon","The Sun"]', 2, 'The Moon is Earth''s natural satellite and orbits around it.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Why do the stars appear to move across the night sky?', '["The Moon pushes them along","The Sun pulls them at night","Earth rotates while the stars stay in place","The stars fly through space quickly"]', 2, 'Earth''s rotation makes the stars seem to move across the sky during the night.', 10),
  ('science', '5', 2, '5.solar', NULL, 'What gives a star like the Sun its light and heat?', '["Energy made deep inside the star","Reflected light","Burning wood","Lightning storms"]', 0, 'Stars produce their own light and heat from energy created in their cores.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which list shows objects in order from smallest to largest?', '["Sun, Earth, Moon","Earth, Sun, Moon","Sun, Moon, Earth","Moon, Earth, Sun"]', 3, 'The Moon is smaller than Earth, and Earth is much smaller than the Sun.', 10),
  ('science', '5', 2, '5.matter', NULL, 'A liquid takes the shape of its container but keeps the same ___.', '["Container","Shape","Volume","Temperature"]', 2, 'A liquid changes shape to fit its container but its volume stays the same.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which is a sign that a chemical change has happened?', '["A balloon is filled with air","Water is poured into a cup","A new gas bubbles out as a reaction occurs","Ice melts into water"]', 2, 'Producing a new gas is a clue that a chemical change has created a new substance.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which change makes a brand-new substance?', '["Iron rusting into reddish flakes","Crushing a can","Cutting paper into pieces","Melting butter"]', 0, 'Rusting is a chemical change because the iron turns into a new substance.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Which of these has a mass that you could measure on a balance?', '["An idea","A shadow","A balloon full of air","A song"]', 2, 'Air is matter and has mass, so a balloon full of air weighs slightly more than an empty one.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'What happens when two forces push an object equally hard in opposite directions?', '["The object changes color","The object does not move","The object flies upward","The object speeds up"]', 1, 'Equal and opposite forces cancel out, so the object stays still (balanced forces).', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Which surface would let a toy car roll the farthest with the least friction?', '["A smooth tile floor","A rough carpet","A grassy yard","A sandy path"]', 0, 'A smooth surface has less friction, so the car rolls farther.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Which change shows a force changing an object''s direction?', '["A box sitting still","A ball slowly stopping","A ball speeding up in a straight line","A rolling ball bouncing off a wall"]', 3, 'When the ball bounces off the wall, a force changes the direction it is moving.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Why do many shoes have rough, bumpy soles?', '["To increase friction so you do not slip","To make you heavier","To remove gravity","To reduce friction so you slide"]', 0, 'Rough soles increase friction with the ground so your feet grip and do not slip.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'In a food chain, the arrow points from food to the eater. What does the arrow show?', '["Which animal is bigger","Where the animal lives","The way energy moves","The direction the animal walks"]', 2, 'Arrows in a food chain show the direction that energy flows from food to eater.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'A food web is different from a food chain because a food web ___.', '["Shows many connected food chains","Only shows the Sun","Has only one animal","Never includes plants"]', 0, 'A food web shows how many food chains in a habitat are connected together.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'Why are decomposers important to a habitat?', '["They make sunlight","They stop the water cycle","They put nutrients back into the soil for plants","They eat all the predators"]', 2, 'Decomposers return nutrients to the soil so plants can grow and use them again.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'Which best shows the correct order of a food chain?', '["Hawk to snake to grass","Hawk to grass to mouse","Grass to mouse to hawk","Mouse to grass to hawk"]', 2, 'Energy flows from the plant (grass) to the plant-eater (mouse) to the predator (hawk).', 10),
  ('science', '5', 2, '5.body', NULL, 'Which body system breaks down food so your body can use it for energy?', '["Skeletal system","Circulatory system","Respiratory system","Digestive system"]', 3, 'The digestive system breaks food down so the body can absorb nutrients and energy.', 10),
  ('science', '5', 2, '5.body', NULL, 'What attaches your muscles to your bones so you can move?', '["Blood vessels","Skin cells","Nerves","Tendons"]', 3, 'Tendons connect muscles to bones, allowing the muscles to move the bones.', 10),
  ('science', '5', 2, '5.body', NULL, 'When you breathe out, your body gets rid of a gas called ___.', '["Helium","Carbon dioxide","Oxygen","Nitrogen only"]', 1, 'The body releases carbon dioxide as a waste gas when you breathe out.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which organs help filter waste out of your blood?', '["Kidneys","Bones","Skin","Eyes"]', 0, 'The kidneys filter waste out of the blood to keep the body healthy.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'When water vapor rises and cools high in the sky, it forms ___.', '["Clouds","Soil","Rocks","Wind"]', 0, 'Cooling water vapor condenses into tiny droplets that form clouds.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Which step of the water cycle returns water from the sky back to Earth''s surface?', '["Precipitation","Evaporation","Drying","Heating"]', 0, 'Precipitation brings water back down to Earth as rain, snow, sleet, or hail.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'During the water cycle, the amount of water on Earth ___.', '["Stays about the same and is recycled","Doubles each year","Keeps increasing","Disappears over time"]', 0, 'The water cycle recycles the same water over and over, so the total amount stays about the same.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Fog is most like which part of the water cycle?', '["Evaporation","Condensation","Freezing","Precipitation"]', 1, 'Fog is made of tiny water droplets formed when water vapor condenses near the ground.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Why does the Sun look bigger and brighter than other stars?', '["It gives off only light","It is much closer to Earth","It is the hottest star","It is the largest star in the universe"]', 1, 'The Sun appears large and bright because it is far closer to Earth than any other star.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which planet is famous for its large, bright rings?', '["Venus","Mercury","Earth","Saturn"]', 3, 'Saturn is best known for its wide, bright system of rings.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which season is it in the part of Earth tilted toward the Sun?', '["There are no seasons","Summer","Fall","Winter"]', 1, 'The part of Earth tilted toward the Sun gets more direct sunlight, giving it summer.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Why is it daytime on one side of Earth while it is nighttime on the other side?', '["The Moon covers half of Earth","The Sun turns off at night","Only one side has the Sun shining on it at a time","Half of Earth is always cloudy"]', 2, 'The Sun can only light the half of Earth facing it, so the other half is in darkness.', 10),
  ('science', '5', 2, '5.matter', NULL, 'When water freezes into ice, what happens to its mass?', '["It becomes zero","It decreases a lot","It stays the same","It increases a lot"]', 2, 'Changing from liquid to solid does not change the amount of matter, so the mass stays the same.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Steam turning back into liquid water on a cold mirror is a ___.', '["Chemical change","Physical change","Burning","New substance"]', 1, 'Steam condensing to liquid water only changes state, so it is a physical change.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which is the smallest continent?', '["Asia","Europe","Africa","Australia"]', 3, 'Australia is the smallest continent.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which continent is almost entirely covered in ice?', '["South America","Africa","Antarctica","Europe"]', 2, 'Antarctica, at the South Pole, is covered in ice.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'The largest country by land area in the world is ___.', '["Egypt","Russia","Italy","the United States"]', 1, 'Russia is the world''s largest country by land area.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Lines that run east–west and measure distance from the equator are lines of ___.', '["longitude","latitude","elevation","color"]', 1, 'Latitude lines run east–west and measure north–south position.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Lines that run north–south from pole to pole are lines of ___.', '["temperature","longitude","latitude","altitude"]', 1, 'Longitude lines run north–south between the poles.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'The equator is located at ___ degrees latitude.', '["0","180","90","45"]', 0, 'The equator is 0° latitude, halfway between the poles.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'The largest hot desert in the world is the ___.', '["Mojave","Everglades","Gobi","Sahara"]', 3, 'The Sahara, in Africa, is the largest hot desert.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'The longest river in the world is generally considered the ___.', '["Thames","Amazon","Mississippi","Nile"]', 3, 'The Nile River in Africa is usually called the world''s longest river.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'The tallest mountain above sea level on Earth is Mount ___.', '["Fuji","Everest","Kilimanjaro","Rainier"]', 1, 'Mount Everest is the highest mountain above sea level.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which ocean is on the WEST coast of the United States?', '["Arctic Ocean","Pacific Ocean","Atlantic Ocean","Indian Ocean"]', 1, 'The Pacific Ocean borders the U.S. west coast.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which U.S. state is a chain of islands in the Pacific Ocean?', '["Hawaii","Florida","Texas","Ohio"]', 0, 'Hawaii is a group of islands in the Pacific.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which continent has the most people living on it?', '["Europe","Australia","Asia","Antarctica"]', 2, 'Asia has the largest population of any continent.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'The largest rainforest in the world is the ___ Rainforest.', '["Amazon","Sahara","Mojave","Arctic"]', 0, 'The Amazon Rainforest in South America is the largest.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'The imaginary line at 0° longitude is called the ___.', '["Tropic of Cancer","equator","Prime Meridian","date line"]', 2, 'The Prime Meridian is 0° longitude.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which is the largest U.S. state by land area?', '["Alaska","Texas","California","Florida"]', 0, 'Alaska is the largest U.S. state by area.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'The half of the Earth north of the equator is called the ___.', '["Northern Hemisphere","Eastern Hemisphere","Southern Hemisphere","Western Hemisphere"]', 0, 'The equator splits Earth into the Northern and Southern Hemispheres.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'When writing a location, latitude is usually given before ___.', '["altitude","the scale","longitude","elevation"]', 2, 'Coordinates are written latitude first, then longitude.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'The imaginary line at about 23 degrees north latitude is called the Tropic of ___.', '["Leo","Aries","Capricorn","Cancer"]', 3, 'The Tropic of Cancer is the line of latitude about 23 degrees north of the equator.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'A place located at 0 degrees latitude and 0 degrees longitude sits where two famous lines cross. Those lines are the equator and the ___.', '["prime meridian","international date line","Tropic of Cancer","Arctic Circle"]', 0, 'The point 0,0 is where the equator meets the prime meridian.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'A place at 40 degrees north, 75 degrees west would be found in which hemisphere east-to-west?', '["Eastern Hemisphere","Western Hemisphere","Polar Hemisphere","Southern Hemisphere"]', 1, 'A west longitude places it in the Western Hemisphere.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A piece of land surrounded by water on all sides is called a(n) ___.', '["plateau","peninsula","island","isthmus"]', 2, 'An island has water on every side.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'The place where a river flows into a larger body of water, often dropping soil, is called a ___.', '["ridge","source","canyon","delta"]', 3, 'A delta forms from soil a river drops where it meets a sea or lake.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A part of an ocean or sea that reaches into the land, with land around much of it, is a ___.', '["gulf","mesa","plateau","peninsula"]', 0, 'A gulf is a large body of ocean water partly surrounded by land.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A large body of fresh water with land all around it is a ___.', '["bay","lake","strait","gulf"]', 1, 'A lake is water surrounded by land, usually fresh water.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A row of connected mountains is called a mountain ___.', '["plain","range","basin","delta"]', 1, 'A mountain range is a chain of mountains close together.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'The Great Lakes are mostly located in which U.S. region?', '["Pacific Northwest","Southeast","Midwest","Southwest"]', 2, 'The Great Lakes border several Midwestern states.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Florida is shaped like a ___ that sticks out into the water.', '["peninsula","plateau","canyon","island"]', 0, 'Florida is a peninsula with water on three sides.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which ocean lies along the EAST coast of Florida?', '["Arctic Ocean","Pacific Ocean","Atlantic Ocean","Indian Ocean"]', 2, 'The Atlantic Ocean borders Florida''s eastern coast.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'On which continent is the country of Brazil located?', '["North America","South America","Africa","Australia"]', 1, 'Brazil is the largest country in South America.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which continent lies directly south of the United States across Central America?', '["Africa","Europe","South America","Antarctica"]', 2, 'South America is south of North America, connected by Central America.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which ocean separates North America from Europe?', '["Indian Ocean","Pacific Ocean","Atlantic Ocean","Arctic Ocean"]', 2, 'The Atlantic Ocean lies between North America and Europe.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'The Pyramids of Giza are a famous landmark in which country?', '["Italy","Egypt","India","Mexico"]', 1, 'The Pyramids of Giza are located in Egypt.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'The prime meridian divides the Earth into the Eastern Hemisphere and the ___.', '["Western Hemisphere","Polar Hemisphere","Northern Hemisphere","Southern Hemisphere"]', 0, 'The prime meridian at 0 degrees longitude separates the Eastern and Western Hemispheres.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'The imaginary line at about 23 degrees south latitude is called the Tropic of ___.', '["Capricorn","Gemini","Cancer","Pisces"]', 0, 'The Tropic of Capricorn is the line of latitude about 23 degrees south of the equator.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Most of South America is located in which hemisphere north-to-south?', '["Southern Hemisphere","Eastern Hemisphere","Western Hemisphere","Northern Hemisphere"]', 0, 'Most of South America lies south of the equator.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'What is the highest number a line of latitude can reach?', '["100 degrees","180 degrees","90 degrees","360 degrees"]', 2, 'Latitude goes from 0 degrees at the equator up to 90 degrees at each pole.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A piece of land that has water on three sides is a ___.', '["mountain","valley","peninsula","island"]', 2, 'A peninsula is connected to land on one side and has water on the other three.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'The starting point of a river, often high in the mountains, is its ___.', '["mouth","delta","source","bank"]', 2, 'A river begins at its source and flows to its mouth.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A narrow strip of land that connects two larger land areas is an ___.', '["island","estuary","inlet","isthmus"]', 3, 'An isthmus is a thin land bridge between two larger pieces of land.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A point of land that sticks out into the water is called a ___.', '["valley","gulf","cape","basin"]', 2, 'A cape is a piece of land that juts out into a sea or ocean.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which ocean borders the East Coast of the United States?', '["Arctic Ocean","Indian Ocean","Atlantic Ocean","Pacific Ocean"]', 2, 'The Atlantic Ocean lies along the eastern coast of the United States.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which large river flows through the middle of the United States and empties into the Gulf of Mexico?', '["Colorado River","Columbia River","Hudson River","Mississippi River"]', 3, 'The Mississippi River runs north to south through the central U.S. to the Gulf of Mexico.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which U.S. state lies far to the north and is separated from the rest of the country by Canada?', '["Alaska","Maine","Washington","Hawaii"]', 0, 'Alaska is the northernmost state and is reached by crossing Canada.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which body of water lies along the WEST coast of Florida?', '["Gulf of Mexico","Lake Erie","Pacific Ocean","Atlantic Ocean"]', 0, 'The Gulf of Mexico borders Florida''s western coast.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'The chain of small islands stretching from the southern tip of Florida is called the Florida ___.', '["Banks","Keys","Falls","Capes"]', 1, 'The Florida Keys are a string of islands off southern Florida.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which is the largest ocean on Earth?', '["Atlantic Ocean","Arctic Ocean","Pacific Ocean","Indian Ocean"]', 2, 'The Pacific is the largest and deepest ocean.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'On which continent would you find the countries of France and Germany?', '["Africa","Asia","Australia","Europe"]', 3, 'France and Germany are both in Europe.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'What is the capital city of France?', '["Berlin","Madrid","Paris","Rome"]', 2, 'Paris is the capital of France.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which continent has no permanent human residents and is mostly used for research stations?', '["Australia","Africa","Europe","Antarctica"]', 3, 'Antarctica has only temporary research crews, not permanent towns.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which continent is located entirely in the Southern Hemisphere and is also a single country?', '["Africa","Europe","Australia","Asia"]', 2, 'Australia is both a continent and a country, lying in the Southern Hemisphere.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'The United States is located in which two hemispheres?', '["Northern and Eastern","Southern and Western","Southern and Eastern","Northern and Western"]', 3, 'The United States lies north of the equator and west of the prime meridian.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'A place at 30 degrees south latitude is located in which hemisphere?', '["Western Hemisphere","Northern Hemisphere","Eastern Hemisphere","Southern Hemisphere"]', 3, 'South latitudes are below the equator in the Southern Hemisphere.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Which kind of line would you read to learn how far a place is east or west of the prime meridian?', '["latitude","a contour line","longitude","the equator"]', 2, 'Longitude measures distance east or west of the prime meridian.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Lines of latitude are also sometimes called ___.', '["meridians","legends","scales","parallels"]', 3, 'Latitude lines run parallel to the equator, so they are called parallels.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'What is the largest number a line of longitude can reach?', '["360 degrees","180 degrees","90 degrees","45 degrees"]', 1, 'Longitude runs from 0 to 180 degrees east and 0 to 180 degrees west.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A low area of land between hills or mountains is a ___.', '["valley","peak","plateau","delta"]', 0, 'A valley is the lower land between higher ground.', 10),
