  ('geography', '5', 2, 'geo.5.physical', NULL, 'A slow-moving mass of ice on land is called a ___.', '["glacier","river","spring","reef"]', 0, 'A glacier is a huge, slow-moving sheet or river of ice.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'Hills of sand piled up by the wind, often near a beach or desert, are called ___.', '["reefs","cliffs","ridges","dunes"]', 3, 'Wind blows sand into mounds called dunes.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which country shares the long northern border of the United States?', '["Russia","Canada","Mexico","Cuba"]', 1, 'Canada lies directly north of the mainland United States.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'The Rocky Mountains are found in which U.S. region?', '["West","Southeast","Midwest","Northeast"]', 0, 'The Rocky Mountains run through the western United States.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'The desert in the American Southwest where you might find cactus and very hot summers is found near which state?', '["Ohio","Vermont","Maine","Arizona"]', 3, 'Arizona is in the dry, hot Southwest desert region.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'What is the largest freshwater lake entirely within the state of Florida?', '["Lake Tahoe","Great Salt Lake","Lake Michigan","Lake Okeechobee"]', 3, 'Lake Okeechobee is the largest lake in Florida.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'Which U.S. region includes states like Georgia, Alabama, and Mississippi?', '["Midwest","Northeast","Southeast","West"]', 2, 'Georgia, Alabama, and Mississippi are part of the Southeast region.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'Which is the largest continent by land area?', '["Europe","Africa","Asia","North America"]', 2, 'Asia is the biggest continent in both area and population.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'What is the capital city of Japan?', '["Tokyo","Beijing","Bangkok","Seoul"]', 0, 'Tokyo is the capital of Japan.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'What is the capital city of Canada?', '["Toronto","Ottawa","Montreal","Vancouver"]', 1, 'Ottawa is the capital of Canada.', 10),
  ('geography', '5', 2, 'geo.5.world', NULL, 'What is the capital city of Mexico?', '["Bogota","Havana","Mexico City","Lima"]', 2, 'Mexico City is the capital of Mexico.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Lines of latitude and longitude cross to form a pattern called a ___.', '["key","compass","scale","grid"]', 3, 'Crossing latitude and longitude lines make a grid used to find exact locations.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Lines of longitude all meet at the ___.', '["poles","tropics","equator","prime meridian only"]', 0, 'Longitude lines run from the North Pole to the South Pole and meet there.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'As you travel from the equator toward a pole, the latitude number gets ___.', '["larger","smaller","negative","zero"]', 0, 'Latitude rises from 0 degrees at the equator to 90 degrees at the poles.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'Lines of longitude are also called ___.', '["contours","compass roses","meridians","parallels"]', 2, 'Longitude lines are called meridians.', 10),
  ('geography', '5', 2, 'geo.5.latlong', NULL, 'To find an exact location on Earth, you use a pair of numbers called ___.', '["symbols","regions","borders","coordinates"]', 3, 'Latitude and longitude together are called coordinates.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A large, flat area of high land is called a ___.', '["valley","plateau","bay","gulf"]', 1, 'A plateau is raised flat land that stands above the area around it.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A large area of flat or gently rolling land is called a ___.', '["plain","peak","fjord","cliff"]', 0, 'A plain is a wide, mostly flat stretch of land.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A very dry region that gets little rain is called a ___.', '["wetland","tundra","rainforest","desert"]', 3, 'A desert is a dry place that receives very little precipitation.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'A narrow channel of water that connects two larger bodies of water is a ___.', '["plateau","strait","plain","peninsula"]', 1, 'A strait is a thin waterway joining two larger seas or oceans.', 10),
  ('geography', '5', 2, 'geo.5.physical', NULL, 'Land that is covered by water for much of the year, like a swamp or marsh, is a ___.', '["canyon","wetland","plateau","mesa"]', 1, 'A wetland is soggy land such as a swamp, marsh, or bog.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'How many states are there in the United States today?', '["13","48","52","50"]', 3, 'The United States has 50 states.', 10),
  ('geography', '5', 2, 'geo.5.usa', NULL, 'What is the capital of the state of Florida?', '["Miami","Orlando","Jacksonville","Tallahassee"]', 3, 'Tallahassee is Florida''s capital city.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The war in which the colonies won their independence is the ___.', '["Civil War","World War I","American Revolution","War of the Roses"]', 2, 'The American Revolution won independence from Britain.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Who was the commander of the American army during the Revolution and later the first president?', '["Ulysses S. Grant","Paul Revere","Abraham Lincoln","George Washington"]', 3, 'George Washington led the Continental Army and became the first president.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The document that became the plan of government for the United States is the ___.', '["grocery list","weather report","map of Florida","Constitution"]', 3, 'The U.S. Constitution is the plan for the country''s government.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The first ten amendments to the Constitution are called the ___.', '["Bill of Rights","Rule Book","Pledge","Top Ten List"]', 0, 'The Bill of Rights is the first ten amendments, protecting people''s freedoms.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Abraham Lincoln was president of the United States during the ___.', '["Civil War","Great Depression","Space Race","Revolution"]', 0, 'Lincoln led the country during the Civil War.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The Emancipation Proclamation, issued by Lincoln, declared freedom for ___.', '["all soldiers","all farmers","the colonies","enslaved people"]', 3, 'The Emancipation Proclamation declared that enslaved people would be free.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Pioneers traveling west long ago often journeyed in covered ___.', '["subways","airplanes","wagons","submarines"]', 2, 'Pioneers crossed the country in covered wagons.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'The growth of railroads in the 1800s made travel across the country ___.', '["more expensive than walking","slower","impossible","faster"]', 3, 'Railroads let people and goods cross the country much faster.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The leaders who helped create the United States government are often called the ___.', '["Founding Fathers","Explorers","Pioneers","Governors"]', 0, 'The Founding Fathers helped create the new nation and its government.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The famous battle cry warning that British soldiers were coming is linked to ___.', '["the first railroad","the gold rush","the moon landing","Paul Revere''s ride"]', 3, 'Paul Revere rode to warn that British troops were coming.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Settlers moving west were looking for new ___.', '["airports","video games","land to live and farm on","shopping malls"]', 2, 'Pioneers moved west seeking land to farm and settle.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'In what city was the Declaration of Independence signed in 1776?', '["Philadelphia","Boston","New York City","Washington, D.C."]', 0, 'The Second Continental Congress met in Philadelphia, where the Declaration of Independence was signed in 1776.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'In what year was the U.S. Constitution written at the Constitutional Convention?', '["1812","1787","1865","1776"]', 1, 'Delegates wrote the Constitution at the Constitutional Convention in 1787.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The U.S. Congress is made up of which two parts?', '["The Cabinet and the courts","The army and the navy","The states and the cities","The Senate and the House of Representatives"]', 3, 'Congress has two parts, or houses: the Senate and the House of Representatives.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'At the national level, who can sign a bill into law or reject it with a veto?', '["A governor","A senator","A judge","The president"]', 3, 'The president, head of the executive branch, can sign bills into law or veto them.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'What is the name for the system that lets each branch check the powers of the others?', '["Free trade","Manifest Destiny","Taxation","Checks and balances"]', 3, 'Checks and balances keep any one branch from becoming too powerful.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The American Revolution was a war between the 13 colonies and which country?', '["Spain","Mexico","Great Britain","France"]', 2, 'The colonists fought for independence from Great Britain in the American Revolution.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Why were many colonists angry about British taxes before the Revolution?', '["They had no representatives in Britain''s Parliament","The taxes paid for colonial schools","They paid no taxes at all","The taxes were spent in the colonies"]', 0, 'Colonists protested ''taxation without representation'' because they had no voice in Parliament.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Which country sent soldiers and ships to help the Americans against Britain?', '["Japan","France","Spain only","Russia"]', 1, 'France became an important ally, sending troops, ships, and supplies to the Americans.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'British soldiers were often nicknamed ''Redcoats'' because of their ___.', '["bright red uniforms","red hats","red flags","red boots only"]', 0, 'British soldiers wore bright red coats, earning them the nickname Redcoats.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The treaty that officially ended the Revolutionary War in 1783 was the Treaty of ___.', '["Versailles","Madrid","Paris","London"]', 2, 'The Treaty of Paris in 1783 officially ended the war and recognized American independence.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'In 1803, the United States bought a huge area of land from France in the ___.', '["Louisiana Purchase","Gadsden Purchase","Florida Treaty","Alaska Purchase"]', 0, 'The Louisiana Purchase of 1803 doubled the size of the United States.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'The belief that the United States was meant to spread across the continent was called ___.', '["the New Deal","Manifest Destiny","Reconstruction","the Cold War"]', 1, 'Manifest Destiny was the belief that the U.S. should expand from coast to coast.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'The mail-carrying horseback riders who raced letters across the West in 1860-61 were the ___.', '["Minutemen","Pony Express","Buffalo Soldiers","Wells Fargo Bank"]', 1, 'The Pony Express used relays of horseback riders to carry mail quickly across the West.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Large animals that roamed the Great Plains and were important to many Plains tribes were the ___.', '["reindeer","camels","bison (buffalo)","kangaroos"]', 2, 'Bison, often called buffalo, gave Plains tribes food, clothing, and shelter.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'The United States bought Alaska in 1867 from which country?', '["Spain","Russia","Canada","France"]', 1, 'The United States purchased Alaska from Russia in 1867.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The American Civil War was fought between which two sides?', '["The United States and Great Britain","The United States and France","The colonists and Native Americans","The Northern (Union) states and the Southern (Confederate) states"]', 3, 'The Civil War was fought between the Union (North) and the Confederacy (South).', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Who was the president of the Confederate States during the Civil War?', '["Andrew Jackson","Abraham Lincoln","Jefferson Davis","Robert E. Lee"]', 2, 'Jefferson Davis served as president of the Confederate States of America.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Who was the Union general who later became the 18th U.S. president?', '["Jefferson Davis","Robert E. Lee","Ulysses S. Grant","Stonewall Jackson"]', 2, 'Ulysses S. Grant led the Union army to victory and later became president.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The secret network that helped enslaved people escape to freedom was called the ___.', '["Underground Railroad","Pony Express","Oregon Trail","Transcontinental Railroad"]', 0, 'The Underground Railroad was a network of people and safe houses that helped enslaved people reach freedom.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'When a state left the Union to join the Confederacy, this action was called ___.', '["an election","an amendment","a revolution","secession"]', 3, 'Secession was when Southern states left, or seceded from, the United States.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'Who is known as the ''Father of the Constitution'' for his major role in writing it?', '["Samuel Adams","James Madison","Patrick Henry","John Hancock"]', 1, 'James Madison is called the Father of the Constitution because he wrote much of it and kept careful notes.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'Which freedom is protected by the First Amendment to the Constitution?', '["The right to vote at age 16","Free college","The right to own land","Freedom of speech"]', 3, 'The First Amendment protects freedoms such as speech, religion, and the press.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'Before the Constitution, the United States was governed under which earlier plan?', '["The Mayflower Compact","The Magna Carta","The Bill of Rights","The Articles of Confederation"]', 3, 'The Articles of Confederation were the country''s first plan of government before the Constitution replaced them.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The Constitution begins with three famous words. What are they?', '["We the People","In God We Trust","E Pluribus Unum","Liberty and Justice"]', 0, 'The Constitution opens with ''We the People,'' showing that power comes from the people.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'Who was the first vice president of the United States?', '["Alexander Hamilton","John Adams","Benjamin Franklin","Thomas Jefferson"]', 1, 'John Adams served as the first vice president under George Washington.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'What event in 1773 had colonists dumping tea into Boston Harbor to protest taxes?', '["The Boston Tea Party","The Boston Massacre","The Stamp Act","Paul Revere''s Ride"]', 0, 'At the Boston Tea Party, colonists threw British tea into the harbor to protest taxes.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Who wrote the pamphlet ''Common Sense'' urging the colonies to seek independence?', '["Benjamin Franklin","Patrick Henry","Thomas Paine","John Hancock"]', 2, 'Thomas Paine''s ''Common Sense'' persuaded many colonists to support independence.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Who said the famous words ''Give me liberty, or give me death!''?', '["Patrick Henry","Paul Revere","Nathan Hale","John Adams"]', 0, 'Patrick Henry gave a fiery speech demanding ''liberty or death'' to support the fight for freedom.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'During the hard winter of 1777-78, Washington''s army camped and suffered at which Pennsylvania site?', '["Valley Forge","Bunker Hill","Fort Sumter","Gettysburg"]', 0, 'Washington''s soldiers endured cold and hunger at Valley Forge during the winter of 1777-78.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'What were the well-prepared colonial soldiers ready to fight at a moment''s notice called?', '["Loyalists","Minutemen","Redcoats","Rangers"]', 1, 'Minutemen were colonial militia ready to fight on a minute''s notice.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The Declaration of Independence said all people are created equal and have rights to life, liberty, and the pursuit of ___.', '["happiness","land","power","money"]', 0, 'The Declaration lists rights to life, liberty, and the pursuit of happiness.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Which president sent explorers to map the new land after the Louisiana Purchase?', '["Andrew Jackson","Thomas Jefferson","Abraham Lincoln","George Washington"]', 1, 'President Thomas Jefferson made the Louisiana Purchase and sent explorers west.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'The 1849 rush of people to California hoping to find gold is called the ___.', '["Pony Express","California Gold Rush","Dust Bowl","Oregon Trail"]', 1, 'The California Gold Rush brought thousands west in 1849 to search for gold.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Which law gave settlers free western land if they farmed it for several years?', '["The Homestead Act","The Stamp Act","The Sugar Act","The Tea Act"]', 0, 'The Homestead Act of 1862 offered settlers free land if they lived on and farmed it.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'The covered wagons many pioneers used were sometimes nicknamed ___ because of their shape and white tops.', '["prairie schooners","stagecoaches","ironclads","clipper ships"]', 0, 'Covered wagons were called prairie schooners because their white tops looked like ships on the grassy plains.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'People who moved west to settle and build new lives on the frontier were called ___.', '["British colonists","knights","sailors","pioneers"]', 3, 'Pioneers were the settlers who moved into and settled the western frontier.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'In what year did the Civil War begin?', '["1776","1861","1900","1812"]', 1, 'The Civil War began in 1861 when fighting broke out at Fort Sumter.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'One main cause of the Civil War was a disagreement over the issue of ___.', '["space travel","slavery","baseball","television"]', 1, 'Slavery was a central cause of the conflict between the North and South.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The bloody 1863 battle often seen as the turning point of the Civil War took place at ___.', '["Yorktown","Bunker Hill","Gettysburg","Saratoga"]', 2, 'The Battle of Gettysburg in 1863 was a major Union victory and turning point of the war.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Who escaped slavery and became a famous ''conductor'' on the Underground Railroad?', '["Betsy Ross","Clara Barton","Harriet Tubman","Sacagawea"]', 2, 'Harriet Tubman escaped slavery and guided many others to freedom on the Underground Railroad.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The time after the Civil War when the nation worked to rebuild the South was called ___.', '["Reconstruction","the Gold Rush","the Revolution","the Great Depression"]', 0, 'Reconstruction was the period after the war spent rebuilding the South and the nation.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The Constitution divides the U.S. government into how many branches?', '["Two","Five","Four","Three"]', 3, 'The Constitution created three branches: legislative, executive, and judicial.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The Constitutional Convention met in which famous building in Philadelphia?', '["Independence Hall","Faneuil Hall","Mount Vernon","Monticello"]', 0, 'Independence Hall in Philadelphia was where both the Declaration and the Constitution were created.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'What do we call a change or addition to the Constitution?', '["A bill","A pardon","A treaty","An amendment"]', 3, 'A change or addition to the Constitution is called an amendment.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'What is the main job of the judicial branch?', '["To collect taxes","To decide what laws mean and settle disputes","To lead the army","To write new laws"]', 1, 'The judicial branch, led by the courts, interprets laws and settles legal disputes.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'What is the capital city of the United States today?', '["Washington, D.C.","Philadelphia","New York City","Boston"]', 0, 'Washington, D.C., became the nation''s capital and is home to the federal government.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Who famously rode at night to warn that British soldiers were coming?', '["John Adams","Paul Revere","Thomas Paine","George Washington"]', 1, 'Paul Revere rode to warn colonists that British troops were marching.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'At which 1777 battle did the Americans win a turning-point victory that brought France into the war?', '["The Battle of Saratoga","The Battle of Trenton","The Battle of Yorktown","The Battle of Bunker Hill"]', 0, 'The American win at Saratoga convinced France to join the war as an ally.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Colonists who supported independence from Britain were called what?', '["Loyalists","Tories","Redcoats","Patriots"]', 3, 'Patriots were colonists who supported breaking away from British rule.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Which colonist had the large, bold signature on the Declaration of Independence as president of Congress?', '["Thomas Jefferson","Benjamin Franklin","George Washington","John Hancock"]', 3, 'John Hancock signed his name large and bold as the president of the Continental Congress.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'In 1775, the colonies formed an army and chose George Washington as its ___.', '["king","commander in chief","secretary","governor"]', 1, 'Congress chose George Washington to be commander in chief of the Continental Army.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Which two explorers led an expedition to explore the West after the Louisiana Purchase?', '["Lewis and Sacagawea only","Cabot and Hudson","Lewis and Clark","Pike and Fremont"]', 2, 'Meriwether Lewis and William Clark led the famous expedition to explore the western lands.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Many pioneers traveled west to Oregon along a famous route called the ___.', '["Erie Canal","Oregon Trail","Appalachian Trail","Route 66"]', 1, 'The Oregon Trail was a long wagon route pioneers followed to reach the Oregon Country.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'As settlers moved west, many Native American nations were forced off their ___.', '["schools","cities","ships","traditional lands"]', 3, 'Westward expansion pushed many Native Americans off the lands where they had long lived.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'In 1845, which large area joined the United States as a state, leading to tension with Mexico?', '["Florida","Texas","Maine","Ohio"]', 1, 'Texas joined the United States in 1845, which helped lead to the war with Mexico.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Why did many pioneers travel west in groups of wagons together?', '["To race to the ocean first","Because wagons could only move in groups","Because the law required it","For safety and to help one another on the long trip"]', 3, 'Pioneers formed wagon trains so they could protect and help each other on the dangerous journey.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The Southern states that left the Union formed a new country called the ___.', '["Confederate States of America","Republic of Texas","United Kingdom","New England"]', 0, 'The Southern states that seceded formed the Confederate States of America.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The Civil War started when Confederate forces attacked which fort in South Carolina?', '["Fort McHenry","Fort Sumter","Fort Knox","Fort Ticonderoga"]', 1, 'The war began with the Confederate attack on Fort Sumter in 1861.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Lincoln''s short, famous 1863 speech honoring fallen soldiers is called the ___.', '["Bill of Rights","Gettysburg Address","Star-Spangled Banner","Declaration of Independence"]', 1, 'The Gettysburg Address was Lincoln''s brief but powerful speech given at the Gettysburg battlefield.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Which amendment to the Constitution, added in 1865, ended slavery in the United States?', '["The 1st Amendment","The 13th Amendment","The 2nd Amendment","The 19th Amendment"]', 1, 'The 13th Amendment, ratified in 1865, abolished slavery throughout the United States.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Who founded the American Red Cross after caring for wounded soldiers during the Civil War?', '["Harriet Tubman","Dolley Madison","Clara Barton","Betsy Ross"]', 2, 'Clara Barton nursed Civil War soldiers and later founded the American Red Cross.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'Which branch of government makes the laws of the United States?', '["The military","The executive branch (president)","The legislative branch (Congress)","The judicial branch (courts)"]', 2, 'Congress, the legislative branch, writes and passes the nation''s laws.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'What is the highest court in the United States, part of the judicial branch?', '["The Supreme Court","Congress","The Cabinet","The Senate"]', 0, 'The Supreme Court is the highest court in the nation and leads the judicial branch.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'How many U.S. senators does each state send to the Senate?', '["Two","Ten","One","Three"]', 0, 'Every state, large or small, sends two senators to the U.S. Senate.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'Which document explains the powers of each branch of the U.S. government?', '["The Emancipation Proclamation","The Constitution","The Gettysburg Address","The Declaration of Independence"]', 1, 'The Constitution sets up the three branches and lists their powers.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'How many years is one term for a U.S. president?', '["Ten years","Four years","Six years","Two years"]', 1, 'A president is elected to serve a term of four years.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The Revolutionary War began in 1775 with battles in which two Massachusetts towns?', '["Plymouth and Quincy","Boston and Salem","Lexington and Concord","Trenton and Princeton"]', 2, 'The first battles of the Revolution were fought at Lexington and Concord in 1775.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The major fighting of the Revolutionary War ended in 1781 when the British surrendered at which Virginia town?', '["Richmond","Yorktown","Jamestown","Williamsburg"]', 1, 'The British army surrendered at Yorktown in 1781, ending the major fighting.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'Colonists who stayed loyal to the British king were called what?', '["Loyalists","Minutemen","Patriots","Pilgrims"]', 0, 'Loyalists were colonists who remained loyal to King George III and Britain.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The first ten amendments to the Constitution are called the ___.', '["Declaration","Rule Book","Top Ten","Bill of Rights"]', 3, 'The Bill of Rights is the first ten amendments.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'An ''amendment'' is a ___ to the Constitution.', '["drawing","vacation","change or addition","song"]', 2, 'An amendment is a change or addition to the Constitution.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The system that lets each branch limit the power of the others is called ___.', '["checks and balances","rock and roll","show and tell","give and take"]', 0, 'Checks and balances keep any one branch from getting too much power.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Splitting government into three branches helps make sure no one branch becomes too ___.', '["powerful","friendly","colorful","quiet"]', 0, 'Three branches keep power balanced so no branch becomes too powerful.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Government that serves the WHOLE country is the ___ government.', '["neighborhood","federal (national)","city","school"]', 1, 'The federal government serves the entire country.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'The two parts of Congress are the Senate and the House of ___.', '["Wizards","Governors","Representatives","Mayors"]', 2, 'Congress has two parts: the Senate and the House of Representatives.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Serving on a jury and voting are examples of a citizen''s ___.', '["chores at home","hobbies","sports","civic duties"]', 3, 'Voting and jury service are civic duties of citizens.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The introduction to the Constitution is called the ___.', '["Appendix","Glossary","Index","Preamble"]', 3, 'The Preamble is the opening of the Constitution (''We the People…'').', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The President can reject a law passed by Congress using a ___.', '["map","veto","vote","song"]', 1, 'A veto is the President''s power to reject a law — a check on Congress.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Government that serves just one city or town is ___ government.', '["world","national","federal","local"]', 3, 'Local government serves a single city or town.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'When the President vetoes a bill, Congress can still make it a law by overriding the veto with a vote of how much of each house?', '["A one-tenth vote","Only the Speaker''s vote","A two-thirds vote","One single vote"]', 2, 'Congress can override a presidential veto with a two-thirds vote in both the House and the Senate.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'After the President nominates a Supreme Court justice, who must approve that person?', '["The House of Representatives","The state legislatures","The Vice President alone","The Senate"]', 3, 'The Senate votes to confirm or reject the President''s nominees for the Supreme Court.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Congress is made up of which two parts?', '["The Supreme Court and the lower courts","The governor and the mayor","The Senate and the House of Representatives","The President and the Vice President"]', 2, 'Congress has two parts, called houses: the Senate and the House of Representatives.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'What does the President usually do to turn a bill from Congress into a law?', '["Sign the bill","Show it to the Supreme Court","Read it on television","Mail it to every state"]', 0, 'When the President signs a bill, it becomes a law.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Which group has the power to remove (impeach and convict) a President who breaks the law?', '["The Supreme Court","State governors","Congress","The Cabinet"]', 2, 'Congress can impeach and remove a President, which is a check on the executive branch.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'What is the supreme (highest) law of the United States?', '["A state law","A presidential order","A school rule","The Constitution"]', 3, 'The Constitution is the highest law in the country, and all other laws must agree with it.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'What are the first ten amendments to the Constitution called?', '["The Pledge of Allegiance","The Declaration of Independence","The Preamble","The Bill of Rights"]', 3, 'The first ten amendments are called the Bill of Rights and protect basic freedoms.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'How many amendments does the Constitution have today?', '["3","27","100","10"]', 1, 'The Constitution has been amended 27 times, including the first ten in the Bill of Rights.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'Who is often called the ''Father of the Constitution'' for his important role in writing it?', '["George Washington","Thomas Edison","James Madison","Benjamin Banneker"]', 2, 'James Madison is called the Father of the Constitution for his major role in writing it.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The original Constitution divides the government into three parts. What are these parts called?', '["Counties","Amendments","Branches","States"]', 2, 'The Constitution sets up three branches of government: legislative, executive, and judicial.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Which level of government would build and maintain a city park?', '["Federal government","Local government","No government","State government"]', 1, 'Local governments, like a city, take care of services such as parks and sidewalks.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'What is the capital city of Florida, where the state government meets?', '["Jacksonville","Orlando","Miami","Tallahassee"]', 3, 'Tallahassee is the capital of Florida, where state lawmakers meet.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'The group of lawmakers who make laws for the whole state of Florida is called the state what?', '["Supreme Court","Legislature","County","Cabinet"]', 1, 'The Florida Legislature makes laws for the entire state.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'A county is a part of which level of government?', '["Federal government","International government","State government","Local government"]', 3, 'A county is a type of local government within a state.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Public schools in a community are mostly run and paid for by which levels of government?', '["Only foreign countries","Only the federal government","Only the President","State and local government"]', 3, 'Public schools are mostly run by state and local governments.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Florida sends two senators and a number of representatives to Congress. What does the number of representatives a state gets depend on?', '["The number of beaches it has","The governor''s choice","The age of the state","The size of the state''s population"]', 3, 'States with more people get more representatives in the House of Representatives.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Serving on a jury when called is an example of what?', '["A citizen''s responsibility","A national holiday","A school rule","A type of vote for President"]', 0, 'Serving on a jury is an important responsibility of being a citizen.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Which of these is a responsibility that helps a community stay clean and healthy?', '["Ignoring all rules","Not littering and recycling","Refusing to talk to neighbors","Staying inside all day"]', 1, 'Taking care of the environment by not littering is a citizen''s responsibility.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Paying taxes is best described as what for citizens?', '["A responsibility","A vacation","A freedom","A right"]', 0, 'Paying taxes is a responsibility that helps pay for public services like schools and roads.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Staying informed about your community and what the government is doing is an example of what?', '["A type of money","A foreign custom","A rule only judges follow","A citizen''s responsibility"]', 3, 'Good citizens have a responsibility to stay informed about their community and government.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'The Bill of Rights was added to the Constitution mainly to do what?', '["List the names of all the states","Set the price of food","Choose a new President","Protect the freedoms and rights of the people"]', 3, 'The Bill of Rights was added to protect people''s basic freedoms and rights from the government.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Which branch has the power to declare that a law is unconstitutional?', '["The executive branch","The legislative branch","The judicial branch","The military"]', 2, 'Courts in the judicial branch can decide a law is unconstitutional and strike it down.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Why did the writers of the Constitution divide the government into three branches?', '["So laws would never change","So there would be no need for voting","So no single branch could become too powerful","So only the President could make decisions"]', 2, 'Separating power into three branches keeps any one branch from gaining too much control.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The Vice President serves as the leader of which house of Congress?', '["The House of Representatives","The Supreme Court","The state legislature","The Senate"]', 3, 'The Vice President is the President of the Senate and can break a tie vote there.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The leader of the House of Representatives is called the what?', '["The Speaker of the House","The Attorney General","The Vice President","The Chief Justice"]', 0, 'The Speaker of the House leads the House of Representatives.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The Constitution created a government where citizens vote for leaders to represent them. What is this kind of government called?', '["A kingdom","An empire","A republic","A dictatorship"]', 2, 'In a republic, the people elect representatives to make decisions for them.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'What does the Constitution say must happen if a state law disagrees with the Constitution?', '["Both laws are thrown out","The state law always wins","The President decides by himself","The Constitution wins because it is the highest law"]', 3, 'The Constitution is the supreme law, so any law that disagrees with it is invalid.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Which level of government can make agreements (treaties) with other countries?', '["Federal government","Local government","State government","County government"]', 0, 'Only the federal government can make treaties with other countries.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Who leads the executive branch of the federal government?', '["The Speaker of the House","The President","The governor","The mayor"]', 1, 'The President leads the executive branch of the federal (national) government.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Which level of government runs the national parks, like the Everglades National Park?', '["City government","County government","Federal government","Local government"]', 2, 'National parks are run by the federal government.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Which of these is a responsibility of a good citizen, not just a right?', '["Playing video games","Obeying the laws","Eating breakfast","Watching television"]', 1, 'Obeying the laws is a responsibility that citizens share.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'The right to a fair trial means that a person accused of a crime gets what?', '["To choose their own punishment","To skip court completely","To go straight to jail","A chance to defend themselves in court"]', 3, 'The right to a fair trial lets an accused person defend themselves before a judge or jury.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Which amendment ended slavery in the United States?', '["The 27th Amendment","The 13th Amendment","The 1st Amendment","The 21st Amendment"]', 1, 'The 13th Amendment, added in 1865, ended slavery in the United States.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Respecting the rights and property of other people is an example of what?', '["A type of tax","A responsibility of a good citizen","A school holiday","A national law only police follow"]', 1, 'Respecting others'' rights and property is a responsibility of being a good citizen.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The President is the head of which branch of government?', '["The legislative branch","The executive branch","The judicial branch","The Supreme Court"]', 1, 'The President leads the executive branch, which carries out and enforces the laws.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Which branch has the power to make the laws?', '["The executive branch","The legislative branch","The judicial branch","The Supreme Court"]', 1, 'The legislative branch, called Congress, writes and passes the nation''s laws.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Which of these is a power of the executive branch?', '["Approving amendments","Enforcing the laws","Writing the laws","Holding trials"]', 1, 'The executive branch, led by the President, carries out and enforces the laws.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'How long does a Supreme Court justice usually serve once approved?', '["Only until the next election","For life, as long as they choose to stay","Exactly four years","Exactly two years"]', 1, 'Supreme Court justices serve for life so they can make fair decisions without worrying about elections.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Why is it important that the courts are separate from the people who make the laws?', '["So no one can ever go to court","So judges never have to follow any laws","So judges can decide cases fairly and not just please lawmakers","So the President can pick every law"]', 2, 'Keeping the courts separate helps judges make fair decisions based on the law.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'In which city was the Constitution written?', '["Boston","New York City","Philadelphia","Washington, D.C."]', 2, 'The Constitution was written at a convention held in Philadelphia, Pennsylvania.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'With what three famous words does the Preamble of the Constitution begin?', '["Life and liberty","In God we","Four score and","We the People"]', 3, 'The Preamble begins with ''We the People,'' showing the government''s power comes from the people.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The Constitution divides government power between the national government and the states. What is this sharing of power called?', '["An amendment","Voting","A veto","Federalism"]', 3, 'Federalism is the system in which power is shared between the national government and the states.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'What does it mean that the Constitution is a ''living document''?', '["It can be changed through amendments over time","It is read aloud every day","It can never be changed in any way","It is kept alive in a garden"]', 0, 'The Constitution can be amended, so it can change to meet new needs over time.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The plan of government that came before the Constitution was called the Articles of Confederation. Why was it replaced?', '["It was written in another country","It had too many amendments","It made the national government too weak","It gave the President too much power"]', 2, 'The Articles of Confederation made the national government too weak, so the Constitution replaced it.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Which level of government is responsible for printing the nation''s money?', '["Federal government","State government","County government","Local government"]', 0, 'Only the federal (national) government can print and coin money.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Which level of government would you contact about a stop sign that needs to be fixed on your street?', '["The Supreme Court","Congress","Federal government","Local government"]', 3, 'Local government handles community needs like street signs and roads in your town.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Which of these is a job done by state government?', '["Signing treaties with other countries","Running the state''s highways and driver''s license offices","Leading the U.S. Army","Printing dollar bills"]', 1, 'State governments manage state highways and issue driver''s licenses.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'How many U.S. senators does each state, including Florida, send to Congress?', '["Ten","One","Two","Fifty"]', 2, 'Every state, no matter its size, elects two U.S. senators.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'A city council is part of which level of government?', '["Federal government","National government","Local government","State government"]', 2, 'A city council is part of local government and makes rules for a city.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'The First Amendment protects freedom of religion. What does this mean?', '["Everyone must follow the same religion","People can choose their own religion or no religion","People cannot talk about religion at all","Only adults can have a religion"]', 1, 'Freedom of religion lets people worship as they choose, or not at all.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'What is the difference between a right and a responsibility?', '["A right is a punishment; a responsibility is a reward","A right is a freedom you have; a responsibility is a duty you should do","A right is only for adults; a responsibility is only for children","They mean exactly the same thing"]', 1, 'Rights are freedoms people have, while responsibilities are duties citizens should carry out.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Voting in elections when you are old enough is an example of what?', '["A school subject","A foreign custom","A law that only the President follows","A right and responsibility of citizens"]', 3, 'Voting is both a right and an important responsibility for citizens.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Which amendment gave women the right to vote in the United States?', '["The 13th Amendment","The 1st Amendment","The 27th Amendment","The 19th Amendment"]', 3, 'The 19th Amendment, added in 1920, gave women the right to vote.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Why are rights important in a free country?', '["They protect people''s freedoms from being taken away","They make sure no one has to follow any rules","They give power only to the President","They stop people from voting"]', 0, 'Rights protect people''s freedoms and limit what the government can do to them.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Who has the power to nominate (choose) Supreme Court justices?', '["State governors","The Chief Justice","The Speaker of the House","The President"]', 3, 'The President nominates Supreme Court justices, and the Senate must approve them.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The idea that each branch of government can limit the power of the other branches is called what?', '["Freedom of speech","Separation of church and state","Majority rule","Checks and balances"]', 3, 'Checks and balances let each branch check the power of the others.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'What is a change or addition to the Constitution called?', '["A pledge","A veto","A bill","An amendment"]', 3, 'A change or addition to the Constitution is called an amendment.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'What does the Preamble mean when it says the Constitution will ''establish justice''?', '["Choose a national flag","Set up a fair system of laws and courts","Print money for everyone","Build new roads"]', 1, '''Establish justice'' means creating a fair system of laws and courts for everyone.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Who is usually the leader of a city or town government?', '["The mayor","The governor","A senator","The President"]', 0, 'A mayor is usually the leader of a city or town government.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Which level of government is in charge of the U.S. military and armed forces?', '["State government","City government","Local government","Federal government"]', 3, 'The federal government controls the nation''s military and armed forces.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A place or system where goods and services are bought and sold is a ___.', '["museum","mountain","market","memory"]', 2, 'A market is where buyers and sellers trade goods and services.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'In a market, the price is set by both buyers and ___.', '["the weather","the moon","sellers","teachers only"]', 2, 'Prices come from the interaction of buyers and sellers.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'A bank is a safe place to keep your money and can pay you ___ on savings.', '["homework","stickers","interest","weather"]', 2, 'Banks keep money safe and can pay interest on savings.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Interest is extra money the bank pays you for ___ your money there.', '["hiding","losing","saving","spending"]', 2, 'Interest is a reward for keeping (saving) money in the bank.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'When people focus on the one job they do best, it is called ___.', '["scarcity","specialization","bartering","budgeting"]', 1, 'Specialization is focusing on what you do best, then trading for the rest.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'Countries and people TRADE because no one can produce ___ by themselves.', '["only toys","nothing at all","rain","everything they need"]', 3, 'Trade lets people get goods they don''t or can''t make themselves.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Money people pay to the government to fund services like roads and schools is called ___.', '["allowance","tips","interest","taxes"]', 3, 'Taxes are money paid to the government to pay for public services.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Borrowing money that must be paid back, often with extra, is called taking out a ___.', '["gift","loan","service","tax refund"]', 1, 'A loan is borrowed money you repay, usually with interest.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'If many stores sell the same item, they ___ for customers.', '["hide","compete","vote","sleep"]', 1, 'Sellers compete for customers, which can lower prices.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Public schools, roads, and parks are often paid for with ___.', '["stickers","tax money","homework","candy"]', 1, 'Tax money funds public services like schools, roads, and parks.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'When you put money into a savings account, the bank keeps your money safe and adds a little extra over time. What is that extra money called?', '["Interest","Taxes","Rent","A fee"]', 0, 'Interest is the extra money a bank pays you for keeping your savings with them.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'What is a checking account mainly used for?', '["Borrowing money from the government","Paying for everyday things and bills","Storing money you will never touch","Earning the highest possible interest"]', 1, 'A checking account is used for everyday spending and paying bills.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Banks are able to pay interest to savers partly because they ___.', '["Take money from the government","Print their own new money","Charge people to walk inside","Lend out money to borrowers who pay interest"]', 3, 'Banks lend deposits to borrowers and earn interest, some of which they pass to savers.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'If you borrow money from a bank, the money you borrow is called a ___.', '["Tax","Loan","Gift","Bonus"]', 1, 'Money borrowed from a bank that must be paid back is a loan.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'A person spends more money with their debit card than they actually have in the account. This is called ___.', '["Overdrawing the account","Saving extra money","Earning interest","Making a deposit"]', 0, 'Spending more than your balance is overdrawing, and banks often charge a fee for it.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'In a market, when many people want a toy but stores have only a few left, the price usually ___.', '["Goes up","Stays exactly the same forever","Goes down","Becomes free"]', 0, 'High demand and low supply push prices up.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'Two ice cream shops are next to each other. To get more customers, they compete by lowering prices. This competition usually helps ___.', '["Buyers, who pay less","No one at all","Buyers, who pay much more","Only the government"]', 0, 'Competition among sellers often leads to lower prices for buyers.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A brand-new video game everyone wants just came out, and only a few copies are in stores. What will likely happen to its price?', '["The game will be free","The price will be high","The price will be very low","The price cannot change"]', 1, 'Strong demand with limited supply leads to high prices.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'Which is an example of a producer?', '["A child eating cereal","A shopper buying shoes","A family watching a movie","A baker who makes and sells bread"]', 3, 'The baker produces bread to sell, making them a producer.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'If the demand for umbrellas suddenly rises during a rainy week, sellers may ___.', '["Give umbrellas away free","Lower umbrella prices to almost nothing","Raise the price of umbrellas","Stop selling umbrellas"]', 2, 'When demand rises, sellers can charge higher prices.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'When a worker focuses on doing one specific job that they are good at, this is called ___.', '["Specialization","Taxation","Borrowing","Scarcity"]', 0, 'Specialization means focusing on one task or skill you do well.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'A region that grows lots of oranges but no wheat can still have bread by ___.', '["Growing oranges faster","Trading oranges for wheat from another region","Refusing to eat bread","Making wheat appear by magic"]', 1, 'Regions trade what they have for what they lack.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'How does specialization in a factory usually affect the time it takes to make a product?', '["It stops production","It makes production faster","It makes production much slower","It has no effect at all"]', 1, 'Specialized workers complete their tasks faster, speeding up production.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'Specialization works best when it is combined with ___.', '["Trade","Hiding goods","Doing nothing","Throwing goods away"]', 0, 'Specialists must trade to get the variety of goods they need.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'What is a resource a country has a lot of and can specialize in producing called?', '["A loan payment","A natural advantage","A scarcity","A tax bill"]', 1, 'Having plenty of a resource gives a country a natural advantage in producing it.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Money that people and businesses pay to the government is called ___.', '["Profit","Tips","Taxes","Allowance"]', 2, 'Taxes are payments made to the government.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Why does the government collect taxes?', '["To pay for services that help everyone","To make people poor on purpose","To keep all the money hidden","To buy gifts for one family"]', 0, 'Taxes pay for shared services like schools, roads, and safety.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Police departments that keep communities safe are usually funded by ___.', '["Taxes","Candy sales","One family''s savings","Toy stores"]', 0, 'Public safety services like police are paid for with taxes.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Taxes that pay for building and fixing highways help ___.', '["People travel safely between places","Only the mayor","Hide money from drivers","Stop all cars"]', 0, 'Road taxes fund safe highways for travel.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'A shirt costs $15 with a $1 sales tax. You pay with a $20 bill. How much change should you get?', '["$4","$5","$6","$1"]', 0, '$15 plus $1 tax is $16, and $20 minus $16 is $4 change.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'A person who deposits $100 in a bank wants to take some of it back out. Taking money out of your account is called a ___.', '["Loan","Donation","Deposit","Withdrawal"]', 3, 'A withdrawal is when you take money out of your bank account.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'A card that lets you spend money directly from your own bank account is called a ___.', '["Gift card from a friend","Library card","Debit card","Report card"]', 2, 'A debit card pulls money straight from your own bank account.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Why might a bank pay MORE interest on a savings account than on a checking account?', '["Savings accounts cannot earn interest","Savings money is kept longer so the bank can use it","Banks dislike checking accounts","Checking accounts are illegal"]', 1, 'Money left in savings longer can be lent out, so banks reward it with more interest.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A store has way too many winter coats left over in spring and almost no one is buying. To sell them, the store will probably ___.', '["Charge double","Hide all the coats","Lower the price","Raise the price higher"]', 2, 'When supply is high and demand is low, sellers lower prices to attract buyers.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A person or business that makes goods to sell is called a ___.', '["Producer","Tourist","Consumer","Voter"]', 0, 'A producer makes goods or provides services to sell.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'What is a market?', '["A place or system where goods and services are bought and sold","A type of tax","A place where money is printed","A school for bankers"]', 0, 'A market is where buyers and sellers trade goods and services.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'Which is an example of a consumer?', '["A shop sewing shirts","A factory building cars","A farmer growing wheat","A person buying groceries at the store"]', 3, 'Buying and using groceries makes the person a consumer.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A toy is selling out instantly everywhere. This is a sign that ___.', '["Supply is greater than demand","Demand is greater than supply","No one wants the toy","The toy is being given away"]', 1, 'Selling out means more people want it than there are toys available.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A store raises its prices much higher than nearby stores for the same item. What will customers most likely do?', '["Shop at the cheaper stores instead","Ask the store to raise prices more","Refuse to ever buy that item anywhere","Pay the higher price happily"]', 0, 'Buyers usually go where prices are lower for the same product.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'In a sandwich shop, one worker takes orders, one makes sandwiches, and one runs the register. Dividing the work this way is an example of ___.', '["Scarcity","A loan","Division of labor","A tax"]', 2, 'Dividing tasks among workers is called division of labor.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'Doctors, plumbers, and teachers each train for different jobs. This is an example of people ___.', '["Paying the same taxes","Specializing in different skills","Avoiding all work","Doing the exact same work"]', 1, 'Each person specializes in a particular skill or profession.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'Why might a town that is good at fishing trade fish with a town that is good at farming?', '["So each town gets both fish and crops","Because fishing is illegal","So neither town gets anything","To stop both towns from eating"]', 0, 'Trading lets each town enjoy goods it does not produce.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'A state with warm beaches and a state with snowy mountains can both benefit by ___.', '["Building identical resources","Refusing all visitors","Avoiding each other","Trading goods and tourism with each other"]', 3, 'Different resources let regions trade and benefit from one another.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'A worker who has practiced one skill for years is called a ___ in that skill.', '["Specialist","Taxpayer","Borrower","Consumer"]', 0, 'Someone skilled in one job through practice is a specialist.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'If a toy costs $10 and there is a $1 sales tax, how much do you pay in total?', '["$1","$11","$9","$10"]', 1, 'You add the $1 tax to the $10 price for $11 total.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Public libraries are often free to use because they are paid for by ___.', '["Taxes","Charging high fees","Selling books inside","One rich person each day"]', 0, 'Tax money funds public libraries so people can use them for free.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Which of these is a public good paid for by taxes that anyone can use?', '["A private pool at a house","Your own bedroom","A friend''s lunchbox","A city park"]', 3, 'City parks are public goods funded by taxes for everyone to use.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Which statement about taxes is true?', '["Taxes are never used for schools","Tax money is collected to fund shared community services","Taxes are kept by one person","Only stores pay taxes"]', 1, 'Taxes fund community services that benefit many people.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Why do many people keep their money in a bank instead of at home?', '["It is required by law to keep all money in a bank","It makes the money worth more right away","Banks give the money away for free","It is safer and harder to lose or have stolen"]', 3, 'Banks store money safely so it is less likely to be lost or stolen.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Maria saves $20 each month in her bank account. After 5 months, how much has she put in, not counting interest?', '["$200","$100","$40","$25"]', 1, '$20 times 5 months equals $100 in deposits.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'A credit card lets you buy something now and pay the bank back later. If you do not pay the full amount on time, the bank usually charges you ___.', '["Nothing at all","More allowance","A free gift","Extra interest"]', 3, 'Unpaid credit card balances build up interest that you must pay.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Jamal puts $50 in the bank and earns $2 in interest after one year. How much does he have now?', '["$52","$100","$50","$48"]', 0, '$50 plus $2 of interest equals $52.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Saving money in a bank instead of spending it all today helps you ___.', '["Pay more for everything","Lose your money quickly","Afford bigger things in the future","Avoid ever buying anything"]', 2, 'Saving builds up money so you can afford larger purchases later.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'What does the word demand mean in economics?', '["The color of a product","How much of a product people want to buy","The size of a store","How much of a product is made"]', 1, 'Demand is how much buyers want and will purchase a product.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A person who buys and uses goods and services is called a ___.', '["Mayor","Consumer","Producer","Banker"]', 1, 'A consumer is someone who buys and uses goods and services.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'In a market, the price of an item is decided by ___.', '["Both buyers and sellers","Only the buyers","Only the weather","Only the government in all cases"]', 0, 'Prices come from the actions of both buyers and sellers.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'When there is a lot of a product and few buyers, sellers often must ___ the price to sell it.', '["Hide","Lower","Triple","Raise"]', 1, 'Excess supply and weak demand push prices down.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'Producers and consumers depend on each other because ___.', '["Producers buy from no one","Consumers make goods for producers to use","They never interact","Producers make what consumers want to buy"]', 3, 'Producers create goods, and consumers buy them, so each needs the other.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'Why do people and countries trade with one another?', '["Trading is against the law","No one can make everything they need by themselves","To avoid getting any goods","Everyone can make everything alone"]', 1, 'People trade because they cannot produce everything they need on their own.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'What is one possible downside of a worker specializing in just one task?', '["The worker becomes worse at the task","The job can become boring or repetitive","It always lowers pay to zero","It is impossible to do"]', 1, 'Doing the same task all day can become boring, a downside of specialization.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'A baker is great at baking but not at fixing cars, and a mechanic is the opposite. The best plan for both is to ___.', '["Both quit their jobs","Each do their own specialty and trade services","Each try to do everything alone","Refuse to help each other"]', 1, 'People do best by specializing and trading what they make or do.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'An assembly line lets each worker add one part to a car as it moves past. This is an example of ___.', '["Specialization and division of labor","Paying taxes","Scarcity of cars","Borrowing money"]', 0, 'Assembly lines split work into specialized tasks for each worker.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'Trade lets people enjoy goods they cannot make themselves. This means trade increases ___.', '["The number of taxes only","The variety of goods available","The boredom of shopping","The amount of scarcity"]', 1, 'Trade brings more kinds of goods to people.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'A sales tax is added when you ___.', '["Breathe outside","Buy certain goods at a store","Walk in a park","Sleep at night"]', 1, 'Sales tax is added to the price of many goods you buy.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'A tax taken out of the money people earn from their jobs is called ___.', '["Income tax","Library fee","Sales tax","Allowance"]', 0, 'Income tax is paid on the money people earn from working.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Why do almost all people in a community pay taxes instead of just a few people?', '["Only children should pay","Sharing makes services cost more","Public services help everyone, so the cost is shared","Taxes are just for fun"]', 2, 'Because public services benefit everyone, the cost is shared widely.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'A property tax is a tax that homeowners pay based on the ___.', '["Color of their car","Number of their friends","Day of the week","Value of their home and land"]', 3, 'Property tax is based on the value of land and buildings owned.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'What might happen to public services if a town collected no taxes at all?', '["Services would all become free forever","It would struggle to pay for schools, roads, and safety","Roads would build themselves","Nothing would change"]', 1, 'Without taxes, a town would lack money to fund public services.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'When a bank lends money to someone to buy a house, the borrower usually has to pay back the amount borrowed PLUS extra. What is the extra payment called?', '["A refund","Interest","An allowance","A deposit"]', 1, 'Borrowers pay interest, which is extra money charged for borrowing.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'What does it mean to make a deposit at a bank?', '["To take money out of your account","To borrow money from the bank","To put money into your account","To close your account"]', 2, 'A deposit adds money to your bank account.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Which of these is the best reason to open a savings account?', '["To avoid ever using money again","To keep money safe and let it grow with interest","To make money disappear","To pay more taxes"]', 1, 'Savings accounts keep money safe while it earns interest.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'What is one safe way to keep track of how much money you have in the bank?', '["Hide the account from yourself","Check your account balance regularly","Spend until the card stops working","Guess and never look"]', 1, 'Checking your balance helps you know how much money you have.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Which of these would a bank most likely lend money for?', '["Buying a car","Breathing air","Walking outside","Sleeping at night"]', 0, 'Banks make loans for large purchases like cars and houses.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'Why do sellers sometimes put items on sale for a lower price?', '["To pay more taxes","To break the law","To get more people to buy them","To make people stop buying"]', 2, 'Lower prices attract more buyers, increasing demand.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A farmer grows a huge crop of oranges this year, so there are many more oranges than usual for sale. The price of oranges will most likely ___.', '["Rise sharply","Fall","Stay frozen forever","Disappear"]', 1, 'A large supply with steady demand usually lowers the price.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'Why is competition between businesses often good for customers?', '["It stops businesses from improving","It removes all choices","It always raises prices","It can lead to lower prices and better products"]', 3, 'Competition pushes businesses to offer lower prices and better quality.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Sales tax rates can be different in different states. This means the same item might cost ___.', '["Nothing at all anywhere","A slightly different total in different states","Twice as much only at night","Exactly the same total everywhere"]', 1, 'Different sales tax rates change the final price from state to state.', 10);
